('hello_follow', 'Hello, lead the way!', 0, 0, '', 'Bonjour, je vais vous montrer le chemin !', 'Hallo, führe den Weg!', '你好，带路吧！', '', '¡Hola, guía el camino!', '', 'Привет, веди!'),
('hello_follow', 'Hi, lead the way!', 0, 0, '', 'Salut, montre le chemin!', 'Hi, zeig mir den Weg!', '嗨，带路吧！', '', '¡Hola, guía el camino!', '', 'Прив, веди!'),

('join_group', 'Hey %player, do you want join my group?', 0, 0, '', 'Salut %player, est-ce que tu veux rejoindre mon groupe ?', 'Hey %player, möchtest du meiner Gruppe beitreten?', '嘿，%player，要不要加入我的队伍？', '', 'Oye %player, ¿Quieres unirte a mi grupo?', '', ''),
('join_raid', 'Hey %player, do you want join my group?', 0, 0, '', 'Salut %player, est-ce que tu veux rejoindre mon groupe?', 'Hey %player, möchtest du meinem Schlachtzug beitreten?', '嘿，%player，要不要加入我的团队？', '', 'Oye %player, ¿Quieres unirte a mi banda?', '', ''),

('logout_cancel', 'Logout cancelled!', 0, 0, '', 'Annulation de la déconnexion !', 'Abmeldung abgebrochen!', '退出取消了！', '', 'Cerrar sesión cancelado!', '', 'Логаут отменен!'),
('logout_start', 'I’m logging out!', 0, 0, '', 'Je me déconnecte !', 'Ich melde mich ab!', '我要下线了！', '', '¡Me estoy desconectando!', '', 'Я выхожу из игры!'),

