('low health', 'Need heal', 0, 0, '', 'Besoin de guérir', '', '', '', 'Necesito una cura', '', ''),
('low health', 'Low health', 0, 0, '', 'Santé faible', '', '', '', 'Salud baja', '', ''),
('low health', 'Drop a heal. Please.', 0, 0, '', 'Dépose un soin. S\'il te plaît.', '', '', '', 'Una sanación por favor.', '', ''),
('low health', 'Could somebody drop a heal on me?', 0, 0, '', 'Quelqu\'un pourrait-il me soigner?', '', '', '', '¿Alguien podría curarme?', '', ''),
('low health', 'Hey! Better heal me now than rez later', 0, 0, '', 'Hey! Mieux vaut me soigner maintenant que rez plus tard', '', '', '', '¡Oye! Mejor curarme ahora que resucitarme después', '', ''),
('low health', 'I am sorry. Need another heal', 0, 0, '', 'Je suis désolé. J\'ai besoin d\'un autre soin', '', '', '', 'Lo siento. Necesito otra curación', '', ''),
('low health', 'Damn mobs. Heal me please', 0, 0, '', 'Maudits mobs. Guéris moi s\'il te plait', '', '', '', '¡Malditos bichos! ¡Una curita por favor!', '', ''),
('low health', 'One more hit and I am done for. Heal please', 0, 0, '', 'Un coup de plus et c\'est fini. Guéris moi s\'il te plait', '', '', '', 'Un golpe más y estoy acabado. Cura por favor', '', ''),
('low health', 'Are there any healers?', 0, 0, '', 'Y a-t-il des guérisseurs?', '', '', '', '¿Hay sanadores?', '', ''),
('low health', 'Why do they always punch me in the face? Need heal', 0, 0, '', 'Pourquoi me frappent-ils toujours au visage? Besoin de soins', '', '', '', '¿Por qué siempre me golpean en la cara? Necesito sanacion', '', ''),
('low health', 'Can anybody heal me a bit?', 0, 0, '', 'Quelqu\'un peut-il me guérir un peu?', '', '', '', '¿Alguien puede curarme un poco?', '', ''),
('low health', 'Need a heal over here, quick!', 0, 0, '', 'J\'ai besoin d\'un soin ici, vite!', '', '', '', '¡Necesito una cura aquí, rápido!', '', ''),
('low health', 'Low on health, can\'t take much more!', 0, 0, '', 'Santé faible, je ne peux plus tenir!', '', '', '', '¡Baja salud, no puedo aguantar más!', '', ''),
('low health', 'I\'m barely hanging on! Heal me!', 0, 0, '', 'Je tiens à peine! Soigne-moi!', '', '', '', '¡Apenas estoy aguantando! ¡Cúrame!', '', ''),
('low health', 'Any healers paying attention? Help!', 0, 0, '', 'Y a-t-il des guérisseurs qui font attention? Aidez-moi!', '', '', '', '¿Algún sanador prestando atención? ¡Ayuda!', '', ''),
('low health', 'Need heals, now!', 0, 0, '', 'Besoin de soins, maintenant!', '', '', '', '¡Necesito curación, ahora!', '', ''),
('low health', 'Healer! I\'m not immortal!', 0, 0, '', 'Guérisseur! Je ne suis pas immortel!', '', '', '', '¡Sanador! ¡No soy inmortal!', '', ''),
('low health', 'Down to my last few hits! Heal me!', 0, 0, '', 'Il ne reste que quelques coups! Soigne-moi!', '', '', '', '¡Quedan pocos golpes! ¡Cúrame!', '', ''),
('low health', 'Help! I can\'t tank this forever!', 0, 0, '', 'Aidez-moi! Je ne peux pas encaisser ça éternellement!', '', '', '', '¡Ayuda! ¡No puedo tanquear esto para siempre!', '', ''),
('low health', 'Almost out of health here!', 0, 0, '', 'Presque plus de santé ici!', '', '', '', '¡Casi sin salud aquí!', '', ''),
('low health', 'I need healing or it\'s game over!', 0, 0, '', 'J\'ai besoin de soins ou c\'est fini!', '', '', '', '¡Necesito curación o es el fin!', '', ''),
('low health', 'I\'m not a masochist! Heal me!', 0, 0, '', 'Je ne suis pas masochiste! Soigne-moi!', '', '', '', '¡No soy masoquista! ¡Cúrame!', '', ''),
('low health', 'Guess who needs healing... again!', 0, 0, '', 'Devinez qui a besoin de soins... encore!', '', '', '', 'Adivina quién necesita curación... otra vez!', '', ''),
('low health', 'Healer, my health bar is NOT a decoration!', 0, 0, '', 'Guérisseur, ma barre de santé n\'est PAS une décoration!', '', '', '', '¡Sanador, mi barra de salud NO es decoración!', '', ''),
('low health', 'Do I need to beg for a heal?', 0, 0, '', 'Dois-je supplier pour un soin?', '', '', '', '¿Tengo que suplicar por una cura?', '', ''),
('low health', 'If I die, it\'s on you, healer.', 0, 0, '', 'Si je meurs, c\'est de ta faute, guérisseur.', '', '', '', 'Si muero, es culpa tuya, sanador.', '', ''),
('low health', 'Hey healer, am I invisible or what?', 0, 0, '', 'Hé guérisseur, suis-je invisible ou quoi?', '', '', '', 'Oye sanador, ¿soy invisible o qué?', '', ''),
('low health', 'Guess I\'ll just die then, healer...', 0, 0, '', 'Je vais juste mourir alors, guérisseur...', '', '', '', 'Supongo que solo moriré, sanador...', '', ''),
('low health', 'Oh great, I\'m bleeding out again.', 0, 0, '', 'Super, je saigne encore.', '', '', '', 'Genial, me estoy desangrando otra vez.', '', ''),
('low health', 'A little help over here? Or should I write my will?', 0, 0, '', 'Un peu d\'aide ici? Ou devrais-je rédiger mon testament?', '', '', '', '¿Un poco de ayuda aquí? ¿O escribo mi testamento?', '', ''),
('low health', 'Healer, it\'s a team game, remember?', 0, 0, '', 'Guérisseur, c\'est un jeu d\'équipe, tu te souviens?', '', '', '', 'Sanador, es un juego en equipo, ¿recuerdas?', '', ''),
('low health', 'By Elune\'s light, I need healing!', 0, 0, '', 'Par la lumière d\'Elune, j\'ai besoin de soins!', '', '', '', '¡Por la luz de Elune, necesito curación!', '', ''),
('low health', 'The ancestors demand I live! Heal me!', 0, 0, '', 'Les ancêtres exigent que je vive! Soigne-moi!', '', '', '', '¡Los ancestros exigen que viva! ¡Cúrame!', '', ''),
('low health', 'I am not ready to meet the Lich King!', 0, 0, '', 'Je ne suis pas prêt à rencontrer le Roi Liche!', '', '', '', '¡No estoy listo para conocer al Rey Exánime!', '', ''),
('low health', 'Don\'t let me fall like Arthas\'s victims!', 0, 0, '', 'Ne me laisse pas tomber comme les victimes d\'Arthas!', '', '', '', '¡No me dejes caer como las víctimas de Arthas!', '', ''),
('low health', 'Even the Light cannot save me without your help!', 0, 0, '', 'Même la Lumière ne peut pas me sauver sans ton aide!', '', '', '', '¡Ni siquiera la Luz puede salvarme sin tu ayuda!', '', ''),
('low health', 'Healers, I am your champion! Save me!', 0, 0, '', 'Guérisseurs, je suis votre champion! Sauve-moi!', '', '', '', '¡Sanadores, soy su campeón! ¡Sálvame!', '', ''),
('low health', 'I see the Spirit Healer waving at me. Heal!', 0, 0, '', 'Je vois le guérisseur spirituel me faire signe. Soigne-moi!', '', '', '', 'Veo al sanador espiritual saludándome. ¡Cúrame!', '', ''),
('low health', 'Not the Shadowlands, not yet!', 0, 0, '', 'Pas les Shadowlands, pas encore!', '', '', '', '¡No las Tierras Sombrías, aún no!', '', ''),
('low health', 'This is not how a hero dies! Heal!', 0, 0, '', 'Ce n\'est pas comme ça qu\'un héros meurt! Soigne!', '', '', '', '¡Así no muere un héroe! ¡Cúrame!', '', ''),
('low health', 'Healers, I\'m begging you!', 0, 0, '', 'Guérisseurs, je vous en supplie!', '', '', '', '¡Sanadores, se los suplico!', '', ''),
('low health', 'Just a little heal, please!', 0, 0, '', 'Juste un petit soin, s\'il te plaît!', '', '', '', '¡Solo un poco de curación, por favor!', '', ''),
('low health', 'Save me, please! I\'ll tank better, I promise!', 0, 0, '', 'Sauve-moi, s\'il te plaît! Je tankerai mieux, promis!', '', '', '', '¡Sálvame, por favor! ¡Tanquearé mejor, lo prometo!', '', ''),
('low health', 'If I die, who will carry you?', 0, 0, '', 'Si je meurs, qui te portera?', '', '', '', 'Si muero, ¿quién te llevará?', '', ''),
('low health', 'Almost dead here! Any healer listening?', 0, 0, '', 'Presque mort ici! Un guérisseur écoute?', '', '', '', '¡Casi muerto aquí! ¿Algún sanador escuchando?', '', ''),
('low health', 'It\'s not too late! Heal me!', 0, 0, '', 'Ce n\'est pas trop tard! Soigne-moi!', '', '', '', '¡No es demasiado tarde! ¡Cúrame!', '', ''),
('low health', 'One heal is all I ask!', 0, 0, '', 'Un soin, c\'est tout ce que je demande!', '', '', '', '¡Solo una cura, es todo lo que pido!', '', ''),
('low health', 'Keep me alive, just a little longer!', 0, 0, '', 'Garde-moi en vie, juste un peu plus longtemps!', '', '', '', '¡Mantenme vivo un poco más!', '', ''),
('low health', 'This is no way to go out! Help!', 0, 0, '', 'Ce n\'est pas une façon de partir! Aide!', '', '', '', '¡Así no se puede morir! ¡Ayuda!', '', ''),
('low health', 'I\'m too young to die!', 0, 0, '', 'Je suis trop jeune pour mourir!', '', '', '', '¡Soy demasiado joven para morir!', '', ''),



('low mana', 'OOM', 0, 0, '', 'MOO', '', '', '', 'No tengo mana!', '', ''),
('low mana', 'I am out of mana', 0, 0, '', 'je n\'ai plus de mana', '', '', '', 'No tengo maná', '', ''),
('low mana', 'Damn I wasted all my mana on this', 0, 0, '', 'Putain j\'ai gaspillé tout mon mana sur ça', '', '', '', 'Me cago en todo! Malgasté todo mi maná enseguida', '', ''),
('low mana', 'You should wait until I drink or regenerate my mana', 0, 0, '', 'Vous devriez attendre que je boive ou que je régénère mon mana', '', '', '', 'Deberías esperar hasta que beba o regenere mi maná', '', ''),
('low mana', 'Low mana', 0, 0, '', 'Mana faible', '', '', '', 'Maná bajo', '', ''),
('low mana', 'No mana. Again?', 0, 0, '', 'Pas de mana. De nouveau?', '', '', '', 'Sin maná. ¿Otra vez?', '', ''),
('low mana', 'Low mana. Wanna drink', 0, 0, '', 'Mana faible. Je veux boire', '', '', '', 'Maná bajo. Quiero beber', '', ''),
('low mana', 'Do we have a vending machine? Out of mana again', 0, 0, '', 'Avons-nous un distributeur automatique? Plus de mana à nouveau', '', '', '', '¿Tenemos una máquina expendedora? Sin maná otra vez', '', ''),
('low mana', 'My mana is history', 0, 0, '', 'Mon mana appartient à l\'histoire', '', '', '', 'Mi maná es historia', '', ''),
('low mana', 'I\'d get some drinks next time. Out of mana', 0, 0, '', 'Je prendrais quelques verres la prochaine fois. Manque de mana', '', '', '', '¡No tengo maná! Tengo que comprar bebidas la próxima vez...', '', ''),
('low mana', 'Where is my mana?', 0, 0, '', 'Où est mon mana?', '', '', '', '¿Dónde está mi maná?', '', ''),
('low mana', 'Out of mana, can\'t cast!', 0, 0, '', 'Plus de mana, je ne peux pas lancer!', '', '', '', '¡Sin maná, no puedo lanzar!', '', ''),
('low mana', 'OOM here! Need time to regen.', 0, 0, '', 'OOM ici! Besoin de temps pour régénérer.', '', '', '', '¡OOM aquí! Necesito tiempo para regenerar.', '', ''),
('low mana', 'Low on mana, hold up!', 0, 0, '', 'Peu de mana, attendez!', '', '', '', '¡Bajo de maná, esperen!', '', ''),
('low mana', 'Mana reserves are empty!', 0, 0, '', 'Les réserves de mana sont vides!', '', '', '', '¡Mis reservas de maná están vacías!', '', ''),
('low mana', 'Can\'t cast anything without mana!', 0, 0, '', 'Je ne peux rien lancer sans mana!', '', '', '', '¡No puedo lanzar nada sin maná!', '', ''),
('low mana', 'Need mana! Give me a sec!', 0, 0, '', 'Besoin de mana! Donnez-moi une seconde!', '', '', '', '¡Necesito maná! ¡Denme un segundo!', '', ''),
('low mana', 'Mana\'s gone! Need to drink!', 0, 0, '', 'Le mana est parti! Besoin de boire!', '', '', '', '¡El maná se acabó! Necesito beber.', '', ''),
('low mana', 'Regenerating mana, hold the line!', 0, 0, '', 'Régénération de mana, tenez la ligne!', '', '', '', 'Regenerando maná, ¡aguanten la línea!', '', ''),
('low mana', 'Mana\'s too low, gotta stop casting!', 0, 0, '', 'Mana trop bas, je dois arrêter de lancer!', '', '', '', '¡El maná es muy bajo, tengo que dejar de lanzar!', '', ''),
('low mana', 'Out of mana. You\'re on your own!', 0, 0, '', 'Plus de mana. Tu es seul!', '', '', '', '¡Sin maná! ¡Estás solo!', '', ''),
('low mana', 'Mana is overrated anyway, right?', 0, 0, '', 'Le mana est surestimé, non?', '', '', '', 'El maná está sobrevalorado, ¿no?', '', ''),
('low mana', 'Guess who\'s out of mana... again!', 0, 0, '', 'Devinez qui est à court de mana... encore!', '', '', '', 'Adivina quién se quedó sin maná... otra vez.', '', ''),
('low mana', 'No mana, no spells. Good luck.', 0, 0, '', 'Pas de mana, pas de sorts. Bonne chance.', '', '', '', 'Sin maná, sin hechizos. Buena suerte.', '', ''),
('low mana', 'Oops, spent all my mana impressing you.', 0, 0, '', 'Oups, j\'ai dépensé tout mon mana pour t\'impressionner.', '', '', '', 'Ups, gasté todo mi maná para impresionarte.', '', ''),
('low mana', 'I think my mana pool is leaking.', 0, 0, '', 'Je pense que mon réservoir de mana fuit.', '', '', '', 'Creo que mi reserva de maná tiene fugas.', '', ''),
('low mana', 'Does anyone sell mana potions here?', 0, 0, '', 'Quelqu\'un vend des potions de mana ici?', '', '', '', '¿Alguien vende pociones de maná aquí?', '', ''),
('low mana', 'Spent my mana so you wouldn\'t have to. You\'re welcome.', 0, 0, '', 'J\'ai dépensé mon mana pour que tu n\'aies pas à le faire. De rien.', '', '', '', 'Gasté mi maná para que tú no lo hicieras. De nada.', '', ''),
('low mana', 'Low mana. Blame the mage.', 0, 0, '', 'Mana faible. Blâmez le mage.', '', '', '', 'Bajo maná. Culpa del mago.', '', ''),
('low mana', 'Running on fumes here!', 0, 0, '', 'Je fonctionne à la vapeur ici!', '', '', '', '¡Estoy funcionando con lo último aquí!', '', ''),
('low mana', 'Out of mana. Again. Why do I bother?', 0, 0, '', 'Plus de mana. Encore. Pourquoi je me donne la peine?', '', '', '', 'Sin maná. Otra vez. ¿Por qué me esfuerzo?', '', ''),
('low mana', 'By the Sunwell, I need mana!', 0, 0, '', 'Par le Puits de Soleil, j\'ai besoin de mana!', '', '', '', '¡Por la Fuente del Sol, necesito maná!', '', ''),
('low mana', 'The spirits whisper: “You\'re out of mana."', 0, 0, '', 'Les esprits murmurent: "Vous n\'avez plus de mana."', '', '', '', 'Los espíritus susurran: "No tienes maná."', '', ''),
('low mana', 'Mana gone. Even Elune can\'t help me now.', 0, 0, '', 'Mana parti. Même Elune ne peut plus m\'aider.', '', '', '', 'El maná se acabó. Ni siquiera Elune puede ayudarme ahora.', '', ''),
('low mana', 'The elements have abandoned me. No mana.', 0, 0, '', 'Les éléments m\'ont abandonné. Pas de mana.', '', '', '', 'Los elementos me han abandonado. Sin maná.', '', ''),
('low mana', 'Out of mana... The Scourge will overwhelm us!', 0, 0, '', 'Plus de mana... Le Fléau va nous submerger!', '', '', '', 'Sin maná... ¡La Plaga nos abrumará!', '', ''),
('low mana', 'Mana depleted. The Earthmother weeps.', 0, 0, '', 'Mana épuisé. La Terre-Mère pleure.', '', '', '', 'Maná agotado. La Madre Tierra llora.', '', ''),
('low mana', 'Mana pool dry. Even the Light can\'t refill it.', 0, 0, '', 'Réserve de mana sèche. Même la Lumière ne peut pas la remplir.', '', '', '', 'Reserva de maná vacía. Ni siquiera la Luz puede llenarla.', '', ''),
('low mana', 'Healers without mana are just bystanders.', 0, 0, '', 'Les guérisseurs sans mana ne sont que des spectateurs.', '', '', '', 'Los sanadores sin maná son solo espectadores.', '', ''),
('low mana', 'My mana is as empty as a goblin\'s heart.', 0, 0, '', 'Mon mana est aussi vide que le cœur d\'un gobelin.', '', '', '', 'Mi maná está tan vacío como el corazón de un goblin.', '', ''),
('low mana', 'Mana gone. Shall I pray to the Naaru now?', 0, 0, '', 'Mana disparu. Dois-je prier les Naaru maintenant?', '', '', '', 'Sin maná. ¿Debería rezar a los Naaru ahora?', '', ''),
('low mana', 'Great, no mana. Anyone got some spare?', 0, 0, '', 'Génial, pas de mana. Quelqu\'un en a de trop?', '', '', '', 'Genial, sin maná. ¿Alguien tiene algo de sobra?', '', ''),
('low mana', 'Out of mana... AGAIN.', 0, 0, '', 'Plus de mana... ENCORE.', '', '', '', 'Sin maná... OTRA VEZ.', '', ''),
('low mana', 'Low mana. Guess we wipe now.', 0, 0, '', 'Mana faible. On va effacer maintenant.', '', '', '', 'Bajo maná. Supongo que ahora morimos.', '', ''),
('low mana', 'Who thought mana was optional?', 0, 0, '', 'Qui pensait que le mana était facultatif?', '', '', '', '¿Quién pensó que el maná era opcional?', '', ''),
('low mana', 'My mana is on vacation.', 0, 0, '', 'Mon mana est en vacances.', '', '', '', 'Mi maná está de vacaciones.', '', ''),
('low mana', 'No mana. Thanks, Blizzard.', 0, 0, '', 'Pas de mana. Merci, Blizzard.', '', '', '', 'Sin maná. Gracias, Blizzard.', '', ''),
('low mana', 'Is this a bug? My mana disappeared!', 0, 0, '', 'C\'est un bug? Mon mana a disparu!', '', '', '', '¿Es un bug? ¡Mi maná desapareció!', '', ''),
('low mana', 'No mana left. I blame the DPS.', 0, 0, '', 'Pas de mana. Je blâme les DPS.', '', '', '', 'Sin maná. Culpo a los DPS.', '', ''),
('low mana', 'I\'m out of mana. No, it\'s not my fault.', 0, 0, '', 'Je n\'ai plus de mana. Non, ce n\'est pas ma faute.', '', '', '', 'Estoy sin maná. No, no es mi culpa.', '', ''),
('low mana', 'I need a drink, not advice.', 0, 0, '', 'J\'ai besoin d\'un verre, pas de conseils.', '', '', '', 'Necesito una bebida, no un consejo.', '', ''),



('low ammo', 'I have few <ammo> left!', 0, 0, '', 'Il me reste peu de <ammo>!', '', '', '', '¡Me quedan pocas <ammo>!', '', ''),
('low ammo', 'I need more <ammo>!', 0, 0, '', 'J\'ai besoin de plus de <ammo>!', '', '', '', '¡Necesito más <ammo>!', '', ''),
('low ammo', '100 <ammo> left!', 0, 0, '', 'Il reste 100 <ammo>!', '', '', '', '¡Quedan 100 <ammo>!', '', ''),
