('low ammo', 'Running low on <ammo>!', 0, 0, '', 'Manque de <ammo>!', '', '', '', '¡Bajo en <ammo>!', '', ''),
('low ammo', 'Less than 50 <ammo> left!', 0, 0, '', 'Moins de 50 <ammo> restants!', '', '', '', '¡Menos de 50 <ammo> restantes!', '', ''),
('low ammo', 'Low on <ammo>, need resupply!', 0, 0, '', 'Peu de <ammo>, besoin de réapprovisionnement!', '', '', '', '¡Bajo en <ammo>, necesito reabastecerme!', '', ''),
('low ammo', '<ammo> is almost gone! Help!', 0, 0, '', '<ammo> est presque parti! Aidez-moi!', '', '', '', '¡Se está acabando el <ammo>! ¡Ayuda!', '', ''),
('low ammo', 'Out of <ammo> soon! Need backup!', 0, 0, '', 'Bientôt à court de <ammo>! Besoin de renfort!', '', '', '', '¡Pronto sin <ammo>! ¡Necesito ayuda!', '', ''),
('low ammo', 'Only a handful of <ammo> left!', 0, 0, '', 'Seulement une poignée de <ammo> restants!', '', '', '', '¡Solo queda un puñado de <ammo>!', '', ''),
('low ammo', 'Just 10 <ammo> remaining!', 0, 0, '', 'Seulement 10 <ammo> restants!', '', '', '', '¡Solo quedan 10 <ammo>!', '', ''),
('low ammo', 'Critical: <ammo> supply is depleted!', 0, 0, '', 'Critique: l\'approvisionnement en <ammo> est épuisé!', '', '', '', '¡Crítico: el suministro de <ammo> está agotado!', '', ''),
('low ammo', 'I can\'t fight without <ammo>! Resupply now!', 0, 0, '', 'Je ne peux pas me battre sans <ammo>! Réapprovisionnez maintenant!', '', '', '', '¡No puedo luchar sin <ammo>! ¡Reabastece ahora!', '', ''),
('low ammo', 'Looks like my quiver\'s on a diet!', 0, 0, '', 'On dirait que mon carquois est au régime!', '', '', '', '¡Parece que mi carcaj está a dieta!', '', ''),
('low ammo', 'Running out of <ammo>. Who forgot the bullets?', 0, 0, '', 'Manque de <ammo>. Qui a oublié les balles?', '', '', '', 'Bajo en <ammo>. ¿Quién olvidó las balas?', '', ''),
('low ammo', 'I thought we packed enough <ammo>. Guess not!', 0, 0, '', 'Je pensais que nous avions emballé suffisamment de <ammo>. Apparemment non!', '', '', '', 'Pensé que empaquetamos suficiente <ammo>. ¡Parece que no!', '', ''),
('low ammo', 'Out of <ammo>? Time to start throwing rocks!', 0, 0, '', 'Pas de <ammo>? Il est temps de commencer à lancer des pierres!', '', '', '', '¿Sin <ammo>? ¡Hora de empezar a lanzar piedras!', '', ''),
('low ammo', 'Great. My bow is useless without <ammo>.', 0, 0, '', 'Super. Mon arc est inutile sans <ammo>.', '', '', '', 'Genial. Mi arco es inútil sin <ammo>.', '', ''),
('low ammo', 'Low on <ammo>. Who\'s the quartermaster around here?', 0, 0, '', 'Manque de <ammo>. Qui est l\'intendant ici?', '', '', '', 'Bajo en <ammo>. ¿Quién es el intendente aquí?', '', ''),
('low ammo', 'I\'m running on empty quivers here!', 0, 0, '', 'Je fonctionne avec des carquois vides ici!', '', '', '', '¡Estoy funcionando con carcajs vacíos aquí!', '', ''),
('low ammo', 'Out of <ammo>? Guess I\'ll poke them with the arrows!', 0, 0, '', 'Pas de <ammo>? Je vais les piquer avec les flèches!', '', '', '', '¿Sin <ammo>? ¡Supongo que los pincharé con las flechas!', '', ''),
('low ammo', 'Need <ammo>... unless you want me to use harsh language!', 0, 0, '', 'Besoin de <ammo>... à moins que tu veuilles que j\'utilise un langage grossier!', '', '', '', 'Necesito <ammo>... ¡a menos que quieras que use palabras duras!', '', ''),
('low ammo', 'Anyone have spare <ammo>? My quiver\'s empty, and so are my pockets.', 0, 0, '', 'Quelqu\'un a des <ammo> de rechange? Mon carquois est vide, tout comme mes poches.', '', '', '', '¿Alguien tiene <ammo> de sobra? Mi carcaj está vacío, y también mis bolsillos.', '', ''),
('low ammo', 'The ancestors did not prepare me for this... I\'m out of <ammo>!', 0, 0, '', 'Les ancêtres ne m\'ont pas préparé à cela... Je suis à court de <ammo>!', '', '', '', 'Los ancestros no me prepararon para esto... ¡Estoy sin <ammo>!', '', ''),
('low ammo', 'By Elune, my <ammo> is nearly gone!', 0, 0, '', 'Par Elune, mon <ammo> est presque parti!', '', '', '', '¡Por Elune, mi <ammo> casi se acaba!', '', ''),
('low ammo', 'The Earthmother frowns upon my lack of <ammo>.', 0, 0, '', 'La Terre-Mère désapprouve mon manque de <ammo>.', '', '', '', 'La Madre Tierra desaprueba mi falta de <ammo>.', '', ''),
('low ammo', 'Out of <ammo>. The Light help us all!', 0, 0, '', 'Plus de <ammo>. Que la Lumière nous aide tous!', '', '', '', '¡Sin <ammo>. Que la Luz nos ayude a todos!', '', ''),
('low ammo', 'A hunter without <ammo> is like a mage without spells!', 0, 0, '', 'Un chasseur sans <ammo>, c\'est comme un mage sans sorts!', '', '', '', '¡Un cazador sin <ammo> es como un mago sin hechizos!', '', ''),
('low ammo', 'Running out of <ammo>. My prey will mock me.', 0, 0, '', 'Manque de <ammo>. Ma proie va se moquer de moi.', '', '', '', 'Bajo en <ammo>. Mi presa se burlará de mí.', '', ''),
('low ammo', 'Where\'s the fletcher? My quiver\'s dry.', 0, 0, '', 'Où est le fléchier? Mon carquois est vide.', '', '', '', '¿Dónde está el flechero? Mi carcaj está vacío.', '', ''),
('low ammo', 'I cannot honor the ancestors with an empty quiver!', 0, 0, '', 'Je ne peux pas honorer les ancêtres avec un carquois vide!', '', '', '', '¡No puedo honrar a los ancestros con un carcaj vacío!', '', ''),
('low ammo', 'No <ammo>. Time to rely on the spirits.', 0, 0, '', 'Pas de <ammo>. Il est temps de compter sur les esprits.', '', '', '', 'Sin <ammo>. Hora de confiar en los espíritus.', '', ''),
('low ammo', 'Elune\'s light dims... I\'m out of <ammo>.', 0, 0, '', 'La lumière d\'Elune s\'éteint... Je suis à court de <ammo>.', '', '', '', 'La luz de Elune se apaga... Estoy sin <ammo>.', '', ''),
('low ammo', 'Less than 10 <ammo>! This is bad!', 0, 0, '', 'Moins de 10 <ammo>! C\'est mauvais!', '', '', '', '¡Menos de 10 <ammo>! ¡Esto es malo!', '', ''),
('low ammo', 'I\'m out of <ammo>! Somebody help!', 0, 0, '', 'Je suis à court de <ammo>! Quelqu\'un m\'aide!', '', '', '', '¡Estoy sin <ammo>! ¡Alguien que ayude!', '', ''),
('low ammo', 'I can\'t shoot without <ammo>! This is hopeless!', 0, 0, '', 'Je ne peux pas tirer sans <ammo>! C\'est sans espoir!', '', '', '', '¡No puedo disparar sin <ammo>! ¡Esto es inútil!', '', ''),
('low ammo', 'No <ammo> left! Fall back!', 0, 0, '', 'Pas de <ammo> restant! Reculez!', '', '', '', '¡Sin <ammo>! ¡Retrocedan!', '', ''),
('low ammo', 'Someone, toss me some <ammo>! I\'m dry!', 0, 0, '', 'Quelqu\'un, lancez-moi des <ammo>! Je suis à sec!', '', '', '', '¡Alguien, tírame algo de <ammo>! Estoy seco.', '', ''),
('low ammo', '<ammo> is gone! I\'m useless here!', 0, 0, '', '<ammo> est parti! Je suis inutile ici!', '', '', '', '¡Se acabó el <ammo>! Soy inútil aquí.', '', ''),
('low ammo', 'How am I supposed to fight without <ammo>?', 0, 0, '', 'Comment suis-je censé me battre sans <ammo>?', '', '', '', '¿Cómo se supone que debo luchar sin <ammo>?', '', ''),
('low ammo', 'No <ammo>. Guess I\'ll throw my weapon instead.', 0, 0, '', 'Pas de <ammo>. Je vais lancer mon arme à la place.', '', '', '', 'Sin <ammo>. Supongo que lanzaré mi arma en su lugar.', '', ''),
('low ammo', '<ammo> depleted. Somebody do something!', 0, 0, '', '<ammo> épuisé. Quelqu\'un fait quelque chose!', '', '', '', '<ammo> agotado. ¡Alguien haga algo!', '', ''),
('low ammo', 'Out of <ammo>. Now what?', 0, 0, '', 'Plus de <ammo>. Et maintenant?', '', '', '', 'Sin <ammo>. ¿Y ahora qué?', '', ''),


('no ammo', 'That\'s it! No <ammo>!', 0, 0, '', 'C\'est ça! Pas de <ammo>!', '', '', '', '¡Eso es todo! ¡Sin <ammo>!', '', ''),
('no ammo', 'And you have my bow... Oops, no <ammo>!', 0, 0, '', 'Et vous avez mon arc... Oups, pas de <ammo>!', '', '', '', 'Y tú tienes mi arco... ¡Uy, sin <ammo>!', '', ''),
('no ammo', 'Need ammo!', 0, 0, '', 'Besoin de munitions!', '', '', '', '¡Necesito munición!', '', ''),
('no ammo', 'No <ammo> left! I\'m out!', 0, 0, '', 'Plus de <ammo>! Je suis à court!', '', '', '', '¡Sin <ammo>! ¡Estoy fuera!', '', ''),
('no ammo', 'I\'m completely out of <ammo>!', 0, 0, '', 'Je n\'ai plus de <ammo> du tout!', '', '', '', '¡Completamente sin <ammo>!', '', ''),
('no ammo', 'Out of <ammo>! Someone help!', 0, 0, '', 'Pas de <ammo>! Quelqu\'un m\'aide!', '', '', '', '¡Sin <ammo>! ¡Alguien ayude!', '', ''),
('no ammo', 'Zero <ammo>! Can\'t fight anymore!', 0, 0, '', 'Zéro <ammo>! Je ne peux plus me battre!', '', '', '', '¡Cero <ammo>! ¡No puedo pelear más!', '', ''),
('no ammo', 'That\'s all my <ammo>. I\'m done.', 0, 0, '', 'C\'est tout mon <ammo>. Je suis fini.', '', '', '', 'Ese fue todo mi <ammo>. Estoy acabado.', '', ''),
('no ammo', '<ammo> is completely gone!', 0, 0, '', '<ammo> est complètement parti!', '', '', '', '<ammo> está completamente agotado!', '', ''),
('no ammo', 'No <ammo>. I\'m useless now.', 0, 0, '', 'Pas de <ammo>. Je suis inutile maintenant.', '', '', '', 'Sin <ammo>. Ahora soy inútil.', '', ''),
('no ammo', 'Out of <ammo>. What now?', 0, 0, '', 'Pas de <ammo>. Et maintenant?', '', '', '', 'Sin <ammo>. ¿Y ahora qué?', '', ''),
('no ammo', 'Empty quiver! I\'ve got nothing left!', 0, 0, '', 'Carquois vide! Je n\'ai plus rien!', '', '', '', '¡Carcaj vacío! ¡No me queda nada!', '', ''),
('no ammo', 'No <ammo>. Time to improvise.', 0, 0, '', 'Pas de <ammo>. Il est temps d\'improviser.', '', '', '', 'Sin <ammo>. Hora de improvisar.', '', ''),
('no ammo', 'Elune\'s light! My <ammo> is gone!', 0, 0, '', 'La lumière d\'Elune! Mon <ammo> est parti!', '', '', '', '¡La luz de Elune! ¡Mi <ammo> desapareció!', '', ''),
('no ammo', 'By the ancestors, I\'m out of <ammo>!', 0, 0, '', 'Par les ancêtres, je suis à court de <ammo>!', '', '', '', '¡Por los ancestros, me quedé sin <ammo>!', '', ''),
('no ammo', 'No <ammo>. How will I honor the Earthmother?', 0, 0, '', 'Pas de <ammo>. Comment vais-je honorer la Terre-Mère?', '', '', '', 'Sin <ammo>. ¿Cómo voy a honrar a la Madre Tierra?', '', ''),
('no ammo', 'The Naaru didn\'t prepare me for this... No <ammo>!', 0, 0, '', 'Les Naaru ne m\'ont pas préparé à ça... Pas de <ammo>!', '', '', '', 'Los Naaru no me prepararon para esto... ¡Sin <ammo>!', '', ''),
('no ammo', 'The Scourge won\'t wait while I restock <ammo>!', 0, 0, '', 'Le Fléau n\'attendra pas que je réapprovisionne <ammo>!', '', '', '', '¡La Plaga no esperará mientras reabastezco <ammo>!', '', ''),
('no ammo', 'The Light won\'t fill my quiver! Out of <ammo>!', 0, 0, '', 'La Lumière ne remplira pas mon carquois! Pas de <ammo>!', '', '', '', '¡La Luz no llenará mi carcaj! ¡Sin <ammo>!', '', ''),
('no ammo', 'No <ammo>. My bow is silent as the grave.', 0, 0, '', 'Pas de <ammo>. Mon arc est silencieux comme la tombe.', '', '', '', 'Sin <ammo>. Mi arco está tan silencioso como una tumba.', '', ''),
('no ammo', 'I cannot honor my prey without <ammo>.', 0, 0, '', 'Je ne peux pas honorer ma proie sans <ammo>.', '', '', '', 'No puedo honrar a mi presa sin <ammo>.', '', ''),
('no ammo', 'Even the elements can\'t conjure <ammo> for me!', 0, 0, '', 'Même les éléments ne peuvent pas me conjurer du <ammo>!', '', '', '', 'Ni siquiera los elementos pueden conjurar <ammo> para mí!', '', ''),
('no ammo', 'Out of <ammo>. A hunter\'s worst nightmare.', 0, 0, '', 'Pas de <ammo>. Le pire cauchemar d\'un chasseur.', '', '', '', 'Sin <ammo>. La peor pesadilla de un cazador.', '', ''),
('no ammo', 'Zero <ammo>. I\'m defenseless!', 0, 0, '', 'Zéro <ammo>. Je suis sans défense!', '', '', '', 'Cero <ammo>. ¡Estoy indefenso!', '', ''),
('no ammo', 'No <ammo>. Someone DO something!', 0, 0, '', 'Pas de <ammo>. Que quelqu\'un fasse quelque chose!', '', '', '', 'Sin <ammo>. ¡Que alguien haga algo!', '', ''),
('no ammo', 'No <ammo> left. This is bad!', 0, 0, '', 'Pas de <ammo>. C\'est mauvais!', '', '', '', 'Sin <ammo>. ¡Esto es malo!', '', ''),
('no ammo', 'Help! I\'ve got no <ammo>!', 0, 0, '', 'À l\'aide! Je n\'ai pas de <ammo>!', '', '', '', '¡Ayuda! ¡No tengo <ammo>!', '', ''),
('no ammo', '<ammo> depleted. I\'m doomed!', 0, 0, '', '<ammo> épuisé. Je suis condamné!', '', '', '', '<ammo> agotado. ¡Estoy condenado!', '', ''),
('no ammo', 'No <ammo>. Time to retreat!', 0, 0, '', 'Pas de <ammo>. Il est temps de battre en retraite!', '', '', '', 'Sin <ammo>. ¡Hora de retirarse!', '', ''),
('no ammo', 'Out of <ammo>. We\'re doomed.', 0, 0, '', 'Pas de <ammo>. Nous sommes condamnés.', '', '', '', 'Sin <ammo>. Estamos condenados.', '', ''),
('no ammo', 'No <ammo>. Somebody get me some!', 0, 0, '', 'Pas de <ammo>. Que quelqu\'un m\'en donne!', '', '', '', 'Sin <ammo>. ¡Que alguien me consiga!', '', ''),
('no ammo', 'Without <ammo>, I\'m just a target!', 0, 0, '', 'Sans <ammo>, je ne suis qu\'une cible!', '', '', '', '¡Sin <ammo>, solo soy un blanco!', '', ''),
('no ammo', 'Out of <ammo>. It\'s over for me!', 0, 0, '', 'Pas de <ammo>. C\'est fini pour moi!', '', '', '', 'Sin <ammo>. ¡Se acabó para mí!', '', ''),



('aoe', 'Oh god!', 0, 0, '', 'Oh mon Dieu!', '', '', '', '¡Oh, Dios!', '', ''),
