('aoe', 'This is over', 0, 0, '', 'C\'est terminé', '', '', '', 'Esto se acabó', '', ''),
('aoe', 'This ends now', 0, 0, '', 'Cela se termine maintenant', '', '', '', 'Esto termina ahora', '', ''),
('aoe', 'Could somebody cast blizzard or something?', 0, 0, '', 'Quelqu\'un pourrait-il lancer le blizzard ou quelque chose comme ça?', '', '', '', '¿Alguien podría lanzar ventisca o algo así?', '', ''),
('aoe', 'Damn. The tank aggroed all the mobs around', 0, 0, '', 'Mince. Le tank a agro toutes les mobs autour', '', '', '', '¡Me cago en todo! El tanque atrajo a todos los mobs...', '', ''),
('aoe', 'We gonna die. We gonna die. We gonna die.', 0, 0, '', 'Nous allons mourir. Nous allons mourir. Nous allons mourir.', '', '', '', 'Vamos a morir. Vamos a morir. Vamos a morir.', '', ''),
('aoe', 'Whoa! So many toys to play with', 0, 0, '', 'Ouah ! Tant de jouets avec lesquels jouer', '', '', '', '¡Vaya! Tantos juguetes con los que jugar', '', ''),
('aoe', 'I gonna kill them all!', 0, 0, '', 'Je vais tous les tuer!', '', '', '', '¡Voy a matarlos a todos!', '', ''),
('aoe', 'If the tank dies we are history', 0, 0, '', 'Si le tank meurt, nous appartenons à l\'histoire', '', '', '', 'Si el tanque muere somos historia', '', ''),
('aoe', 'Aaaaaargh!', 0, 0, '', 'Aaaaaargh!', '', '', '', '¡Aaaaaargh!', '', ''),
('aoe', 'LEEEEERROOOYYYYYYYYYYYY JENNKINNNSSSSSS!!!!!!!', 0, 0, '', 'LEEEEERROOOYYYYYYYYYYYY JENNKINNNSSSSSS!!!!!!!', '', '', '', 'LEEEEERROOOYYYYYYYYYYYY JENNKINNNSSSSSS!!!!!!!', '', ''),
('aoe', 'Right. What do we have in AOE?', 0, 0, '', 'D\'accord. Qu\'avons-nous en dégats de zone?', '', '', '', 'Claro. ¿Qué tenemos en AOE?', '', ''),
('aoe', 'This gets interesting', 0, 0, '', 'Cela devient intéressant', '', '', '', 'Esto se pone interesante', '', ''),
('aoe', 'Cool. Get them in one place for a good flamestrike', 0, 0, '', 'Cool. Rassemblez-les au même endroit pour un bon coup de flamme', '', '', '', 'Genial! Ponlos todos juntos para un buen ataque en area', '', ''),
('aoe', 'Kill! Kill! Kill!', 0, 0, '', 'Tuer! Tuer! Tuer!', '', '', '', '¡Matar! ¡Matar! ¡Matar!', '', ''),
('aoe', 'I think my pants are wet', 0, 0, '', 'Je pense que mon pantalon est mouillé', '', '', '', 'Creo que mis pantalones están mojados', '', ''),
('aoe', 'We are history', 0, 0, '', 'Nous sommes l\'histoire', '', '', '', 'Somos historia', '', ''),
('aoe', 'I hope healers are ready. Leeeeroy!', 0, 0, '', 'J\'espère que les guérisseurs sont prêts. Leeeeeroy!', '', '', '', 'Espero que los sanadores estén listos. ¡Leeeroy!', '', ''),
('aoe', 'I hope they won\'t come for me', 0, 0, '', 'j\'espère qu\'ils ont gagné, qu\'ils ne viendront pas pour moi', '', '', '', 'Espero que no vengan por mí', '', ''),
('aoe', 'Oh no. I can\'t see at this slaugther', 0, 0, '', 'Oh non. Je ne peux pas voir à ce massacre', '', '', '', 'Oh, no. No puedo ver esta matanza', '', ''),
('aoe', 'Too many mobs! AOE now!', 0, 0, '', 'Trop de mobs! AOE maintenant!', '', '', '', '¡Demasiados mobs! ¡AOE ahora!', '', ''),
('aoe', 'AOE or we\'re toast!', 0, 0, '', 'AOE ou nous sommes cuits!', '', '', '', '¡AOE o estamos fritos!', '', ''),
('aoe', 'Someone drop an AOE, quick!', 0, 0, '', 'Quelqu\'un lâche un AOE, vite!', '', '', '', '¡Alguien lance un AOE, rápido!', '', ''),
('aoe', 'Tank is losing aggro! AOE NOW!', 0, 0, '', 'Le tank perd l\'aggro! AOE MAINTENANT!', '', '', '', '¡El tanque está perdiendo aggro! ¡AOE YA!', '', ''),
('aoe', 'Pull them together for a good AOE!', 0, 0, '', 'Rassemblez-les pour un bon AOE!', '', '', '', '¡Júntalos para un buen AOE!', '', ''),
('aoe', 'AOE them down before they overwhelm us!', 0, 0, '', 'AOE-les avant qu\'ils ne nous submergent!', '', '', '', '¡AOEéalos antes de que nos abrumen!', '', ''),
('aoe', 'We need big damage here! AOE!', 0, 0, '', 'Nous avons besoin de gros dégâts ici! AOE!', '', '', '', '¡Necesitamos mucho daño aquí! ¡AOE!', '', ''),
('aoe', 'Drop everything! Cast your AOE now!', 0, 0, '', 'Laissez tout tomber! Lancez votre AOE maintenant!', '', '', '', '¡Deja todo! ¡Lanza tu AOE ahora!', '', ''),
('aoe', 'Healers, brace yourselves. AOE incoming!', 0, 0, '', 'Guérisseurs, préparez-vous. AOE à venir!', '', '', '', 'Sanadores, prepárense. ¡AOE en camino!', '', ''),
('aoe', 'AOE these mobs before it\'s too late!', 0, 0, '', 'AOE ces mobs avant qu\'il ne soit trop tard!', '', '', '', '¡AOE a estos mobs antes de que sea demasiado tarde!', '', ''),
('aoe', 'Wow, look at all the mobs! Who invited them?', 0, 0, '', 'Wow, regarde tous ces mobs! Qui les a invités?', '', '', '', '¡Vaya, mira a todos esos mobs! ¿Quién los invitó?', '', ''),
('aoe', 'Well, this escalated quickly...', 0, 0, '', 'Eh bien, ça a vite dégénéré...', '', '', '', 'Bueno, esto escaló rápidamente...', '', ''),
('aoe', 'Guess we\'re the buffet now...', 0, 0, '', 'On dirait qu\'on est le buffet maintenant...', '', '', '', 'Parece que somos el buffet ahora...', '', ''),
('aoe', 'AOE now, or say your prayers!', 0, 0, '', 'AOE maintenant, ou dites vos prières!', '', '', '', '¡AOE ahora, o reza tus oraciones!', '', ''),
('aoe', 'Oh great, more friends to play with...', 0, 0, '', 'Oh super, plus d\'amis avec qui jouer...', '', '', '', 'Genial, más amigos para jugar...', '', ''),
('aoe', 'I hope someone packed a bigger fireball...', 0, 0, '', 'J\'espère que quelqu\'un a emballé une plus grosse boule de feu...', '', '', '', 'Espero que alguien tenga una bola de fuego más grande...', '', ''),
('aoe', 'This is fine. Everything is fine...', 0, 0, '', 'C\'est bien. Tout va bien...', '', '', '', 'Esto está bien. Todo está bien...', '', ''),
('aoe', 'It\'s raining mobs! Hallelujah!', 0, 0, '', 'Il pleut des mobs! Alléluia!', '', '', '', '¡Están lloviendo mobs! ¡Aleluya!', '', ''),
('aoe', 'Someone call the janitor. It\'s a mess here!', 0, 0, '', 'Appelez le concierge. C\'est le bordel ici!', '', '', '', '¡Llamen al conserje! ¡Esto es un desastre!', '', ''),
('aoe', 'Tank, you better have a plan...', 0, 0, '', 'Tank, tu ferais mieux d\'avoir un plan...', '', '', '', 'Tanque, más te vale tener un plan...', '', ''),
('aoe', 'By the Light! Unleash AOE now!', 0, 0, '', 'Par la Lumière! Déchaînez AOE maintenant!', '', '', '', '¡Por la Luz! ¡Desata AOE ahora!', '', ''),
('aoe', 'Elune\'s grace, save us from this swarm!', 0, 0, '', 'La grâce d\'Elune, sauvez-nous de cet essaim!', '', '', '', '¡La gracia de Elune, sálvanos de este enjambre!', '', ''),
('aoe', 'The ancestors watch. AOE them down!', 0, 0, '', 'Les ancêtres regardent. AOE-les!', '', '', '', 'Los ancestros miran. ¡Hazles AOE!', '', ''),
('aoe', 'The Scourge will devour us if we don\'t act!', 0, 0, '', 'Le Fléau nous dévorera si nous n\'agissons pas!', '', '', '', '¡El Azote nos devorará si no actuamos!', '', ''),
('aoe', 'Unleash fire and fury upon them!', 0, 0, '', 'Déchaînez le feu et la fureur sur eux!', '', '', '', '¡Desata fuego y furia sobre ellos!', '', ''),
('aoe', 'Even the elements shudder at this chaos!', 0, 0, '', 'Même les éléments tremblent devant ce chaos!', '', '', '', '¡Incluso los elementos tiemblan ante este caos!', '', ''),
('aoe', 'The Naaru won\'t save us from this one. AOE!', 0, 0, '', 'Les Naaru ne nous sauveront pas cette fois. AOE!', '', '', '', 'Los Naaru no nos salvarán de esta. ¡AOE!', '', ''),
('aoe', 'Earthmother, guide us through this slaughter.', 0, 0, '', 'Terre-Mère, guide-nous à travers ce massacre.', '', '', '', 'Madre Tierra, guíanos en esta masacre.', '', ''),
('aoe', 'If this isn\'t the end of days, I don\'t know what is!', 0, 0, '', 'Si ce n\'est pas la fin des temps, je ne sais pas ce que c\'est!', '', '', '', 'Si este no es el fin de los días, no sé qué lo es.', '', ''),
('aoe', 'By fire be purged! AOE now!', 0, 0, '', 'Par le feu, soyez purifiés! AOE maintenant!', '', '', '', '¡Por el fuego, sean purificados! ¡AOE ahora!', '', ''),
('aoe', 'We\'re doomed! Too many mobs!', 0, 0, '', 'Nous sommes condamnés! Trop de mobs!', '', '', '', '¡Estamos condenados! ¡Demasiados mobs!', '', ''),
('aoe', 'I can\'t see anything through all this carnage!', 0, 0, '', 'Je ne peux rien voir à travers ce carnage!', '', '', '', '¡No puedo ver nada con toda esta carnicería!', '', ''),
('aoe', 'Run for your lives!', 0, 0, '', 'Courez pour vos vies!', '', '', '', '¡Corran por sus vidas!', '', ''),
('aoe', 'Oh no, oh no, oh no!', 0, 0, '', 'Oh non, oh non, oh non!', '', '', '', '¡Oh no, oh no, oh no!', '', ''),
('aoe', 'They\'re everywhere! We\'re surrounded!', 0, 0, '', 'Ils sont partout! Nous sommes entourés!', '', '', '', '¡Están por todas partes! ¡Estamos rodeados!', '', ''),
('aoe', 'The mobs are closing in! Help!', 0, 0, '', 'Les mobs se rapprochent! Aidez-moi!', '', '', '', '¡Los mobs se acercan! ¡Ayuda!', '', ''),
('aoe', 'We\'ll be crushed if we don\'t act now!', 0, 0, '', 'Nous serons écrasés si nous n\'agissons pas maintenant!', '', '', '', '¡Seremos aplastados si no actuamos ahora!', '', ''),
('aoe', 'This is chaos! AOE them down now!', 0, 0, '', 'C\'est le chaos! AOE-les maintenant!', '', '', '', '¡Esto es caos! ¡Hazles AOE ahora!', '', ''),
('aoe', 'The tank can\'t hold them all! AOE!', 0, 0, '', 'Le tank ne peut pas tous les retenir! AOE!', '', '', '', '¡El tanque no puede contenerlos a todos! ¡AOE!', '', ''),
('aoe', 'This ends in disaster if we don\'t AOE now!', 0, 0, '', 'Cela se termine en catastrophe si nous ne faisons pas AOE maintenant!', '', '', '', '¡Esto termina en desastre si no hacemos AOE ahora!', '', '');



