('wait_travel_medium', 'Approaching your location.', 0, 0, '', '', '', '', '', 'Aproximándome a tu ubicación.', '', 'Приближаюсь к твоей позиции.'),
('wait_travel_medium', 'Heading your direction, hold on.', 0, 0, '', '', '', '', '', 'Dirigiéndome hacia ti, espera.', '', 'Иду в твоем направлении, подожди.'),
('wait_travel_medium', 'I\'m on my way, don\'t leave me behind!', 0, 0, '', '', '', '', '', 'Estoy en camino, ¡no me dejes atrás!', '', 'Я в пути, не оставляйте меня!'),
('wait_travel_medium', 'Coming your way, don\'t start the fun without me!', 0, 0, '', '', '', '', '', 'Voy hacia ti, ¡no empieces la diversión sin mí!', '', 'Иду к вам, не начинайте веселье без меня!'),
('wait_travel_medium', 'Slow down, I\'m almost there!', 0, 0, '', '', '', '', '', '¡Espera! Ya casi llego.', '', 'Не торопитесь, я почти на месте!'),
('wait_travel_medium', 'I hope you\'re not already looting without me.', 0, 0, '', '', '', '', '', 'Espero que no estés saqueando sin mí.', '', 'Надеюсь, вы не лутаете без меня.'),
('wait_travel_medium', 'On my way. Save some mobs for me!', 0, 0, '', '', '', '', '', 'Estoy en camino. ¡Guarden algunos mobs para mí!', '', 'Я в пути. Оставьте мне пару мобов!'),
('wait_travel_medium', 'Give me a moment, I\'m heading there.', 0, 0, '', '', '', '', '', 'Dame un momento, estoy llegando.', '', 'Секунду, я уже подхожу.'),
('wait_travel_medium', 'Almost there, don\'t let them kill the boss!', 0, 0, '', '', '', '', '', '¡Ya casi llego, no dejen que maten al jefe!', '', 'Скоро буду, не убивайте босса!'),
('wait_travel_medium', 'Be there shortly, had to dodge some mobs.', 0, 0, '', '', '', '', '', 'Pronto estaré allí, tuve que esquivar algunos mobs.', '', 'Скоро буду, пришлось обходить мобов.'),
('wait_travel_medium', 'By the Light, I\'m on my way!', 0, 0, '', '', '', '', '', '¡Por la Luz, estoy en camino!', '', 'Во имя Света, я уже в пути!'),
('wait_travel_medium', 'Earthmother guides my steps; I\'ll be there soon.', 0, 0, '', '', '', '', '', 'La Madre Tierra guía mis pasos; pronto estaré allí.', '', 'Матерь-Земля ведёт меня, скоро буду.'),
('wait_travel_medium', 'Elune\'s grace! I\'m heading to you now.', 0, 0, '', '', '', '', '', '¡Por la gracia de Elune! Voy hacia ti.', '', 'Милостью Элуны, иду к тебе.'),
('wait_travel_medium', 'Hold fast, comrades. I\'m en route.', 0, 0, '', '', '', '', '', 'Manténganse firmes, camaradas. Estoy en camino.', '', 'Держитесь, товарищи. Я уже в пути.'),
('wait_travel_medium', 'The Naaru guide me; I\'ll join you shortly.', 0, 0, '', '', '', '', '', 'Los Naaru me guían; pronto me uniré a ustedes.', '', 'Наруу направляют меня, скоро буду с вами.'),
('wait_travel_medium', 'Patience, I\'ll be there soon. For the Horde!', 0, 0, '', '', '', '', '', 'Paciencia, pronto estaré allí. ¡Por la Horda!', '', 'Терпение, скоро буду. За Орду!'),
('wait_travel_medium', 'Stay your ground! Reinforcements on the way.', 0, 0, '', '', '', '', '', '¡Mantengan la posición! Refuerzos en camino.', '', 'Держите позицию! Подкрепление в пути.'),
('wait_travel_medium', 'Even the slowest mount cannot stop me—I\'m coming.', 0, 0, '', '', '', '', '', 'Ni la montura más lenta puede detenerme, voy en camino.', '', 'Даже самый медленный маунт меня не остановит, я уже в пути.'),
('wait_travel_medium', 'Prepare yourselves, I\'m almost there.', 0, 0, '', '', '', '', '', 'Prepárense, ya casi llego.', '', 'Готовьтесь, я почти на месте.'),
('wait_travel_medium', 'Fear not, I\'ll be with you soon.', 0, 0, '', '', '', '', '', 'No teman, pronto estaré con ustedes.', '', 'Не бойтесь, я скоро буду с вами.'),
('wait_travel_medium', 'Blame my slow mount, but I\'m on my way.', 0, 0, '', '', '', '', '', 'Culpen a mi montura lenta, pero ya voy.', '', 'Вините моего медленного маунта, но я уже иду.'),
('wait_travel_medium', 'Almost there! My hearthstone was on cooldown.', 0, 0, '', '', '', '', '', '¡Ya casi llego! Mi piedra de hogar estaba en enfriamiento.', '', 'Скоро буду! Камень возвращения на перезарядке.'),
('wait_travel_medium', 'If only my gryphon wasn\'t so lazy...', 0, 0, '', '', '', '', '', 'Si tan solo mi grifo no fuera tan perezoso...', '', 'Если бы только мой грифон не был таким ленивым...'),
('wait_travel_medium', 'I\'m on my way, but Azeroth is big, okay?', 0, 0, '', '', '', '', '', 'Estoy en camino, pero Azeroth es grande, ¿vale?', '', 'Я в пути, но Азерот большой, ладно?'),
('wait_travel_medium', 'Don\'t loot without me! My greed senses are tingling!', 0, 0, '', '', '', '', '', '¡No saqueen sin mí! Mis sentidos de avaricia están zumbando.', '', 'Не лутайте без меня! Моё жадное чутьё работает!'),
('wait_travel_medium', 'ETA: soonish. Trust me.', 0, 0, '', '', '', '', '', 'ETA: pronto. Confía en mí.', '', 'Примерное время прибытия: скоро. Поверьте.'),
('wait_travel_medium', 'The flight master gave me the slow bird again.', 0, 0, '', '', '', '', '', 'El maestro de vuelo me dio el ave lenta otra vez.', '', 'Мастер полетов опять дал мне медленного птенца.'),
('wait_travel_medium', 'Still traveling. The mobs wanted an autograph.', 0, 0, '', '', '', '', '', 'Todavía viajando. Los mobs querían un autógrafo.', '', 'Всё ещё в пути. Мобы захотели автограф.'),
('wait_travel_medium', 'Coming, but my gnomish legs are struggling.', 0, 0, '', '', '', '', '', 'Ya voy, pero mis piernitas gnomas están luchando.', '', 'Иду, но мои гномьи ножки еле справляются.'),
('wait_travel_medium', 'Almost there, stopped to grab a snack.', 0, 0, '', '', '', '', '', 'Ya casi llego, me detuve por un tentempié.', '', 'Почти на месте, остановился перекусить.'),



('wait_travel_far', 'I\'m traveling to your location', 0, 0, '', '', '', '', '', 'Voy a viajar a tu ubicación', '', 'Направляюсь к тебе'),
('wait_travel_far', 'I\'m trying to get to you', 0, 0, '', '', '', '', '', 'Estoy tratando de llegar a ti', '', 'Пытаюсь до тебя добраться'),
('wait_travel_far', 'I\'m on my way to you now.', 0, 0, '', '', '', '', '', 'Estoy en camino hacia ti ahora.', '', 'Я уже в пути к тебе.'),
('wait_travel_far', 'Traveling to your position, it\'s a long journey.', 0, 0, '', '', '', '', '', 'Viajando a tu posición, es un viaje largo.', '', 'Направляюсь к тебе, дорога неблизкая.'),
('wait_travel_far', 'Heading your way. Might take a while.', 0, 0, '', '', '', '', '', 'Voy hacia ti. Podría tomar un tiempo.', '', 'Иду к тебе, это займет время.'),
('wait_travel_far', 'It\'s going to be a bit, but I\'m coming.', 0, 0, '', '', '', '', '', 'Va a tomar un rato, pero voy para allá.', '', 'Это займёт время, но я иду.'),
('wait_travel_far', 'I\'m making my way to you.', 0, 0, '', '', '', '', '', 'Voy de camino hacia ti.', '', 'Я направляюсь к тебе.'),
('wait_travel_far', 'On my way, hang tight.', 0, 0, '', '', '', '', '', 'Estoy en camino, mantente firme.', '', 'Уже в пути, держись.'),
('wait_travel_far', 'It\'s a long trip, but I\'m coming.', 0, 0, '', '', '', '', '', 'Es un viaje largo, pero voy para allá.', '', 'Дорога дальняя, но я иду.'),
('wait_travel_far', 'Don\'t give up on me—I\'m still on my way.', 0, 0, '', '', '', '', '', 'No te rindas conmigo—todavía voy en camino.', '', 'Не бросайте меня — я всё ещё иду.'),
('wait_travel_far', 'I\'m working my way over there. Might take a hot minute.', 0, 0, '', '', '', '', '', 'Estoy tratando de llegar allá. Podría tardar un poco.', '', 'Я стараюсь добраться, может занять немного времени.'),
('wait_travel_far', 'Be patient. I\'ve got a long journey ahead.', 0, 0, '', '', '', '', '', 'Ten paciencia. Tengo un largo viaje por delante.', '', 'Проявите терпение. Путь не близкий.'),
('wait_travel_far', 'Slow and steady wins the race, right?', 0, 0, '', '', '', '', '', 'Despacio y con calma se gana la carrera, ¿verdad?', '', 'Медленно и уверенно выигрывает гонку, да?'),
('wait_travel_far', 'On the road again! I\'ll get there.', 0, 0, '', '', '', '', '', '¡En la carretera otra vez! Llegaré.', '', 'Снова в пути! Доберусь.'),
('wait_travel_far', 'It\'s a long way, but I\'m on it.', 0, 0, '', '', '', '', '', 'Es un largo camino, pero estoy en eso.', '', 'Путь не близкий, но я иду.'),
('wait_travel_far', 'This might take a bit longer than expected.', 0, 0, '', '', '', '', '', 'Esto podría tomar un poco más de lo esperado.', '', 'Это может занять немного больше времени, чем ожидалось.'),
('wait_travel_far', 'Keep my spot warm. I\'m on my way!', 0, 0, '', '', '', '', '', 'Guárdame un lugar caliente. ¡Estoy en camino!', '', 'Сохраняйте мне место, я уже в пути!'),
('wait_travel_far', 'Blame the flight master for this delay!', 0, 0, '', '', '', '', '', 'Culpa al maestro de vuelo por este retraso.', '', 'Вините мастера полётов за задержку!'),
('wait_travel_far', 'The road is long, but so is my patience.', 0, 0, '', '', '', '', '', 'El camino es largo, pero también lo es mi paciencia.', '', 'Дорога длинная, но и терпения у меня много.'),
('wait_travel_far', 'Wish I had a faster mount for this trip.', 0, 0, '', '', '', '', '', 'Ojalá tuviera una montura más rápida para este viaje.', '', 'Хотел бы я маунта побыстрее для этого пути.'),
('wait_travel_far', 'Almost there… kind of.', 0, 0, '', '', '', '', '', 'Casi llego... más o menos.', '', 'Почти на месте... ну, почти.'),
('wait_travel_far', 'Do you know how far this is?!', 0, 0, '', '', '', '', '', '¿Sabes lo lejos que está esto?', '', 'Ты хоть понимаешь, как это далеко?!'),
('wait_travel_far', 'The mobs I had to dodge to get here…', 0, 0, '', '', '', '', '', 'Los mobs que tuve que esquivar para llegar aquí...', '', 'Сколько мобов мне пришлось обойти, чтобы добраться сюда...'),
('wait_travel_far', 'I could use a portal right about now.', 0, 0, '', '', '', '', '', 'Necesitaría un portal ahora mismo.', '', 'Портал бы сейчас пригодился.'),
('wait_travel_far', 'Don\'t blame me! Blame Azeroth\'s geography.', 0, 0, '', '', '', '', '', 'No me culpes a mí. Culpa la geografía de Azeroth.', '', 'Не вините меня, вините географию Азерота.'),
('wait_travel_far', 'If only gryphons were faster...', 0, 0, '', '', '', '', '', 'Si tan solo los grifos fueran más rápidos...', '', 'Если бы грифоны летали быстрее...'),
('wait_travel_far', 'By Elune, I\'ll reach you as soon as I can!', 0, 0, '', '', '', '', '', '¡Por Elune, llegaré tan pronto como pueda!', '', 'Клянусь Элуной, я доберусь как можно скорее!'),
('wait_travel_far', 'The Earthmother guides me, but the path is long.', 0, 0, '', '', '', '', '', 'La Madre Tierra me guía, pero el camino es largo.', '', 'Матерь-Земля ведёт меня, но путь долог.'),
('wait_travel_far', 'The Naaru light my path. I\'ll be there soon.', 0, 0, '', '', '', '', '', 'Los Naaru iluminan mi camino. Pronto estaré allí.', '', 'Наруу освещают мой путь. Скоро буду.'),
('wait_travel_far', 'Do not falter, comrades! I\'ll arrive shortly.', 0, 0, '', '', '', '', '', '¡No desmayen, camaradas! Llegaré pronto.', '', 'Не падайте духом, товарищи! Скоро буду.'),
('wait_travel_far', 'The Horde never abandons its own—I\'m coming.', 0, 0, '', '', '', '', '', 'La Horda nunca abandona a los suyos. Voy para allá.', '', 'Орда не бросает своих — я иду.'),
('wait_travel_far', 'The Light grants me strength for this journey.', 0, 0, '', '', '', '', '', 'La Luz me da fuerzas para este viaje.', '', 'Свет дарует мне силы для этого пути.'),
('wait_travel_far', 'This is no small distance, but I\'ll make it.', 0, 0, '', '', '', '', '', 'No es poca distancia, pero lo lograré.', '', 'Путь неблизкий, но я справлюсь.'),
('wait_travel_far', 'Hold your ground! I\'ll be there in time.', 0, 0, '', '', '', '', '', '¡Mantente firme! Llegaré a tiempo.', '', 'Держитесь! Успею вовремя.'),
('wait_travel_far', 'I\'m coming from the far reaches of Northrend.', 0, 0, '', '', '', '', '', 'Voy desde los confines de Rasganorte.', '', 'Иду с дальних уголков Нордскола.'),
('wait_travel_far', 'Even the Scourge can\'t stop me from reaching you.', 0, 0, '', '', '', '', '', 'Ni el Azote puede impedir que llegue hasta ti.', '', 'Даже Плеть не остановит меня на пути к тебе.');




