INSERT INTO `ai_playerbot_texts` (`name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
('broadcast_looting_item_poor', 'nooo, I got %item_link', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'aww not this trash again %item_link', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'seem to be looting trash %item_link', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'well, it\'s better than nothing I guess %item_link', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'not sure what to do with %item_link', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Ugh, another %item_link. What did I do to deserve this?', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'This %item_link isn\'t even worth selling.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Great, just what I needed. More garbage: %item_link.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'I\'ve seen better loot in a trash heap.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Looks like my luck ran out. %item_link is all I get.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'What am I supposed to do with %item_link? Seriously.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Not again! %item_link, you haunt me.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Guess I\'ll just add %item_link to the pile.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'If disappointment had a name, it would be %item_link.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Another day, another useless %item_link.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'I bet no one else even wants %item_link.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Why do I always get stuck with %item_link?', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'This %item_link should come with a refund.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Oh look, more junk: %item_link.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', '%item_link is about as useful as a broken sword.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Guess I\'ll keep %item_link… for sentimental reasons?', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Well, at least %item_link doesn\'t smell bad.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'This is not what I signed up for! %item_link again?', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'My inventory is now 10% %item_link and 90% despair.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Maybe I can trade %item_link for something better… like a stick.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'This %item_link will make a fine doorstop.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'You\'d think they\'d at least polish %item_link before giving it out.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'I guess %item_link is better than nothing. Barely.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', '%item_link? Really? I demand a recount!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'I wouldn\'t wish %item_link on my worst enemy.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Is %item_link cursed? Because it sure feels like it.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Well, this %item_link is going straight to the scrap dealer.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Why do I even bother? %item_link isn\'t worth the effort.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'The only thing worse than %item_link is two of them.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', '%item_link just screams "mediocrity."', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Oh… %item_link? Well, I guess it\'s better than absolutely nothing.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'I had high hopes… but all I got was %item_link.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Hey, at least it\'s shiny! Oh, wait, it\'s just %item_link.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'I\'m not crying, it\'s just… dust. And %item_link.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Yay! Oh… it\'s just %item_link. Never mind.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'I didn\'t know disappointment had a physical form: %item_link.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Could\'ve been worse. Wait… no, it couldn\'t. %item_link is the worst.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Well, %item_link isn\'t going to sell itself… if it sells at all.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Huh, %item_link. I guess that\'s what luck looks like. Bad luck.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Oh no… not %item_link. Anything but that!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'I suppose %item_link will make a fine placeholder until something better comes along.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'What\'s this? %item_link? Hah, good one.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'This isn\'t loot; it\'s a practical joke. %item_link? Seriously?', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'If you squint really hard, %item_link almost looks valuable.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'I bet someone out there might actually want %item_link. Not me, though.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Oh look, it\'s %item_link! … Wait, why am I excited?', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'This %item_link is so bad, even a vendor might refuse it.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'I guess %item_link could double as a paperweight.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'Who left %item_link lying around? Oh, right. Fate did.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_looting_item_poor', 'I\'ll keep %item_link… as a reminder to lower my expectations.', 0, 0, '', '', '', '', '', '', '', ''),
INSERT INTO `ai_playerbot_texts` (`name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
('broadcast_quest_accepted_generic', 'I have just taken the %quest_link', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'just accepted %quest_link', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link gonna try to complete this one', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'took %quest_link in %zone_name', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'yay! I got %quest_link! I\'m gonna be the best %my_class ever!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'whoa! %quest_link sounds super cool! I can\'t wait!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'just picked %quest_link! Does it come with a pony?', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'I\'ll show the Lich King who\'s boss with %quest_link!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link is my mission! Time to be awesome!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'by me beard, %quest_link is a quest worthy of a stout heart!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'ah, %quest_link! A fine excuse to swing me hammer.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'took %quest_link in %zone_name. Time to make me ancestors proud!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'if %quest_link doesn\'t end in ale, I\'ll be disappointed.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'this %quest_link better lead to treasure. Or a fight. Preferably both.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'ya mon, %quest_link be callin\' for da power of da Loa.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link? I\'ll take it and show da Lich King who\'s boss, mon.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'dis %quest_link feels like it got a lil voodoo in it.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'accepted %quest_link in %zone_name. Gonna smash some Scourge!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link sounds dangerous. Just how I like it.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'the spirits guide me to take %quest_link.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'accepted %quest_link in %zone_name. It feels like the Earthmother\'s will.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'this %quest_link will bring balance to the land. I will see it done.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'such wisdom in %quest_link. A true test for a humble %my_class.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'I walk with the winds to complete %quest_link.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'I have taken %quest_link, a challenge worthy of my grace.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'the magic in %quest_link calls to me. I must answer.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link is as intricate as the spires of Silvermoon.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'I took %quest_link in %zone_name. May it lead to honor.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link whispers of ancient power. I cannot resist.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link feels like a small light in this endless dark.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'even in %zone_name, where the land weeps, %quest_link offers hope.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link reminds me of the battles we\'ve lost… and the ones we must win.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'I took %quest_link, but I can\'t forget what\'s at stake.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'Northrend is cruel, but %quest_link might bring some peace.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'great, %quest_link. Exactly what I needed. More chores.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'wow, %quest_link. Sure hope it\'s worth the effort.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'guess I\'ll just add %quest_link to my never-ending to-do list.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'oh, %quest_link. Another glorious errand. Fantastic.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'because nothing screams "hero" like taking %quest_link.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link is perfect! The voices agree!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'ha! %quest_link is the first step in my glorious rise!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'I\'ll take %quest_link and turn it into a masterpiece of chaos!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'finally, %quest_link. The key to unlocking everything!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link shall be mine, and with it, I shall ascend!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link feels like it was meant for me… or my corpse.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'even the undead have work to do. I took %quest_link.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link might lead to something worthwhile. Or more rot.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'I accepted %quest_link in %zone_name. Let\'s see how this ends.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'this %quest_link reeks of undeath. Just the way I like it.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link? Sounds like a profit waiting to happen!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'cha-ching! %quest_link looks like a goldmine to me.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'accepted %quest_link. If it doesn\'t explode, it\'s a win.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'you\'re telling me %quest_link pays out? I\'m in.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link better not cost me more than I make.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'uh… %quest_link? Sure! What\'s it about again?', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'yay! I took %quest_link. I hope it\'s not scary.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link sounds hard… but I\'ll try!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'I just got %quest_link! Does it involve food?', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link? I\'ll just follow someone else and hope for the best.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'just picked up %quest_link. Time to get to work.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'accepted %quest_link. Wonder how long this will take.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'took %quest_link in %zone_name. Let\'s see what happens.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link seems important. Better not mess this up.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link is on the list now. One step at a time.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link feels like the right thing to do. I\'ll see it through.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'even in this dark place, %quest_link gives me hope.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'I accepted %quest_link. It\'s a small light in the shadow of Northrend.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link is more than a quest. It feels like a calling.', 0, 0, '', '', '', '', '', '', '', ''),
