('broadcast_quest_accepted_generic', 'took %quest_link. Let\'s see if I can survive %zone_name.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link? I\'ll finish it before the Scourge even notices.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link is tied to the horrors of Icecrown. I\'m ready.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'accepted %quest_link in %zone_name. The Lich King will regret this.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link leads through %area_name? That place gives me chills.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'oh great, %quest_link. Another errand for the heroes.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'just took %quest_link. Why does it feel like busywork?', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link? Sure, I\'ve got nothing better to do. Really.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link is the perfect way to waste a perfectly good day.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'great, %quest_link. I\'ll probably get a broken sword as a reward.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link is calling me! The madness grows stronger!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'ha! %quest_link is the first step in my glorious reign!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'took %quest_link. Now the chaos truly begins.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link whispers secrets… and I will answer!', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'accepted %quest_link. The end of the world begins now.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link is a challenge, but I\'ll rise to meet it.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'I accepted %quest_link in %zone_name. We can\'t give up now.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'took %quest_link. One quest closer to saving Northrend.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', '%quest_link will help us push back the darkness.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'accepted %quest_link. Every victory counts, no matter how small.', 0, 0, '', '', '', '', '', '', '', '');
