('suggest_trade', 'I sold all my %category yesterday. I am completely broke!', 0, 0, '', 'Jai vendu tout mon %category hier. Je suis complètement fauché!', '', '', '', 'Ayer vendí todo mi %category. ¡Estoy completamente arruinado!', '', ''),
('suggest_trade', 'Wanna join a guild farming for %category.', 0, 0, '', 'Je veux rejoindre une guilde farmant pour %category', '', '', '', 'Quiero unirme a una hermandad de farmeo para %category.', '', '');
INSERT INTO `ai_playerbot_texts` (`name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
('suggest_faction', 'Anyone farming %faction rep?', 0, 0, '', 'Quelquun farm la réput de %faction ?', '', '', '', '¿Alguien farmea reputación con %faction?', '', ''),
('suggest_faction', 'Anyone help with %faction?', 0, 0, '', 'Quelquun aide-t-il %faction ?', '', '', '', '¿Alguien me ayuda con %faction?', '', ''),
('suggest_faction', 'Wanna quest for %faction.', 0, 0, '', 'Je veux quêter %faction', '', '', '', 'Quiero buscar a %faction.', '', ''),
('suggest_faction', '%faction is the best.', 0, 0, '', '%faction est la meilleure.', '', '', '', '%faction es el mejor.', '', ''),
('suggest_faction', 'Need just a bit to be %rep_level with %faction.', 0, 0, '', 'Jai besoin dun peu pour être au %rep_level avec %faction', '', '', '', 'Solo necesito un poco para estar %rep_level con %faction.', '', ''),
('suggest_faction', 'Anyone got %rep_level with %faction?', 0, 0, '', 'Quelquun a-t-il %rep_level avec %faction ?', '', '', '', '¿Alguien tiene %rep_level con %faction?', '', ''),
('suggest_faction', 'Who wants to be %rep_level with %faction?', 0, 0, '', 'Qui veut être au %rep_level avec %faction ?', '', '', '', '¿Quién quiere estar en %rep_level con %faction?', '', ''),
('suggest_faction', 'Ill never be %rep_level with %faction.', 0, 0, '', 'Je ne serai jamais au %rep_level avec %faction', '', '', '', 'Nunca estaré %rep_level con %faction.', '', ''),
('suggest_faction', 'Someone missing %faction rep?', 0, 0, '', 'Quelquun manque de reput de %faction ?', '', '', '', '¿Alguien falta reputación con %faction?', '', ''),
('suggest_faction', 'Could help farming %faction rep.', 0, 0, '', 'Pourrait aider à farmer réput de %faction', '', '', '', 'Podría ayudar a farmear %faction rep.', '', ''),
('suggest_faction', 'The more rep the better. Especially with %faction.', 0, 0, '', 'Plus il y a de réput, mieux cest. Surtout avec %faction', '', '', '', 'Cuantas más repeticiones, mejor. Especialmente con %faction.', '', ''),
('suggest_faction', '%faction: need %rndK for %rep_level.', 0, 0, '', '%faction: besoin %rndK pour %rep_level.', '', '', '', '%faction: necesita %rndK para %rep_level.', '', ''),
('suggest_faction', 'Who can share %faction quests?', 0, 0, '', 'Qui peut partager les quêtes de %faction ?', '', '', '', '¿Quién puede compartir misiones de %faction?', '', ''),
('suggest_faction', 'Any dungeons for %faction?', 0, 0, '', 'Des donjons pour %faction ?', '', '', '', '¿Alguna mazmorra para %faction?', '', ''),
('suggest_faction', 'Wanna do %faction rep grind.', 0, 0, '', 'Je veux faire monter ma réput %faction', '', '', '', 'Quiero hacer %faction rep grind.', '', ''),
('suggest_faction', 'Lets farm %faction rep!', 0, 0, '', 'Farmons la réput %faction !', '', '', '', '¡Vamos a farmear reputación con %faction!', '', ''),
('suggest_faction', 'Farming for %faction rep.', 0, 0, '', 'Farmons pour la réput %faction', '', '', '', 'Farming for %faction rep.', '', ''),
('suggest_faction', 'Wanna farm for %faction.', 0, 0, '', 'Je veux farmer pour %faction', '', '', '', 'Quiero farmear para %faction.', '', ''),
('suggest_faction', 'Need help with %faction.', 0, 0, '', 'Besoin daide avec %faction', '', '', '', 'Necesito ayuda con %faction.', '', ''),
('suggest_faction', 'Is %faction sells something useful?', 0, 0, '', 'Est-ce que %faction vend quelque chose dutile ?', '', '', '', '¿%faction vende algo útil?', '', ''),
('suggest_faction', 'Are there %faction vendors?', 0, 0, '', 'Y a-t-il des vendeurs %faction ?', '', '', '', '¿Hay %proveedores de facciones?', '', ''),
('suggest_faction', 'Who farms %faction?', 0, 0, '', 'Qui farm %faction ?', '', '', '', '¿Quién farmea %faction?', '', ''),
('suggest_faction', 'Which is the best way to farm %faction?', 0, 0, '', 'Quelle est la meilleure façon de farmer %faction ?', '', '', '', '¿Cuál es la mejor manera de farmear %faction?', '', ''),
('suggest_faction', 'I hate %faction rep grind.', 0, 0, '', 'Je déteste le travail de %faction rep.', '', '', '', 'Odio %repetir de facción', '', ''),
('suggest_faction', 'I am so tired of %faction.', 0, 0, '', 'Je suis tellement fatigué de %faction', '', '', '', 'Estoy tan cansado de %faction.', '', ''),
('suggest_faction', 'Go for %faction?', 0, 0, '', 'Vous optez pour %faction ?', '', '', '', '¿Quereis ir a por %faction?', '', ''),
('suggest_faction', 'Seems everyone is %rep_level with %faction. Only me is late as usually.', 0, 0, '', 'On dirait que tout le monde est %rep_level avec %faction Il n\'y a que moi qui suis en retard comme d\'habitude.', '', '', '', 'Parece que todo el mundo está %rep_level con %faction. Solo yo llego tarde como siempre.', '', ''),
('suggest_faction', 'LFG for %faction rep grind?', 0, 0, '', 'Cherche un groupe pour monter la réput des représentants de %faction ?', '', '', '', 'Busco grupo para subir reputación con %faction', '', ''),
('suggest_faction', 'Can anobody suggest a good spot for %faction rep grind?', 0, 0, '', 'Quelquun peut-il suggérer un bon endroit pour monter les réput de %faction ?', '', '', '', '¿Alguien puede sugerir un buen lugar farmear reputacion con %faction?', '', ''),
('suggest_faction', 'Would %faction rep benefit me?', 0, 0, '', 'Est-ce que la réput %faction me serait bénéfique ?', '', '', '', '¿Me beneficiaría subir reputación con %faction?', '', ''),
('suggest_faction', 'Who wouldve thought that %faction rep will be useful after all...', 0, 0, '', 'Qui aurait pensé que le représentant de %faction serait utile après tout...', '', '', '', 'Quién hubiera pensado que subir reputacion con %faction sería útil después de todo...', '', ''),
('suggest_faction', 'I wanna be exalted with all factions, starting with %faction.', 0, 0, '', 'Je veux être exalté avec toutes les factions, à commencer par %faction', '', '', '', 'Quiero ser exaltado con todas las facciones, comenzando con %faction.', '', ''),
('suggest_faction', 'Is there any point to improve my rep with %faction?', 0, 0, '', 'Y a-t-il un intérêt à améliorer ma réputation avec %faction ?', '', '', '', '¿Hay algún punto para mejorar mi reputación con %faction?', '', ''),
('suggest_faction', 'What is better for %faction? Quests or mob grinding?', 0, 0, '', 'Quoi de mieux pour %faction ? Quêtes ou mob pour XP?', '', '', '', '¿Qué es mejor para %faction? ¿Misiones o mafiosos?', '', ''),
('suggest_faction', 'Will grind %faction rep for you. Just give me some gold.', 0, 0, '', 'Monte la reput de %faction pour vous. Donnez-moi juste de lor.', '', '', '', 'Ganare reputacion con %faction por ti. Sólo dame un poco de oro.', '', ''),
('suggest_faction', 'I think grinding rep with %faction would take forever.', 0, 0, '', 'Je pense que monter la réput avec %faction prendrait une éternité.', '', '', '', 'Creo que subir la reputación con %faction tomaría una eternidad.', '', ''),
('suggest_faction', 'I am killing for %faction every day now but still far from %rep_level.', 0, 0, '', 'Je tue pour %faction tous les jours maintenant, mais encore loin du %rep_level', '', '', '', 'Estoy matando por %faction todos los días ahora, pero aún estoy lejos del %rep_level.', '', ''),
('suggest_faction', 'At %my_level AH deposits will decrease, right?', 0, 0, '', 'Au %rep_level, les dépôts hôtel des ventes diminueront, nest-ce pas?', '', '', '', 'Al %rep_level, los depósitos subastas disminuirán, ¿verdad?', '', ''),
('suggest_faction', 'How many exalted reps do you have?', 0, 0, '', 'Combien de représentants exaltés avez-vous ?', '', '', '', '¿Cuántas reputaciones exaltadas tienes?', '', ''),
('suggest_faction', 'Who wants to be %my_level with %faction?', 0, 0, '', 'Qui veut être au %rep_level avec %faction ?', '', '', '', '¿Quién quiere estar en %rep_level con %faction?', '', ''),
('suggest_faction', 'Damn. My guild did a good %faction grind yesterday without me.', 0, 0, '', 'Mince. Ma guilde a fait un bon travail de %faction hier sans moi.', '', '', '', 'Maldición. Mi hermandad hizo un buen farmeo de %faction ayer sin mí.', '', ''),
('suggest_faction', 'Nobody wants to help me because I am %rep_level with %faction.', 0, 0, '', 'Personne ne veut maider parce que je suis %rep_level avec %faction', '', '', '', 'Nadie quiere ayudarme porque estoy %rep_level con %faction.', '', ''),
('suggest_faction', 'Please stay away from %faction.', 0, 0, '', 'Veuillez rester à lécart de %faction', '', '', '', 'Por favor manténgase alejado de %faction.', '', ''),
('suggest_faction', 'Do the Kirin Tor even notice my work? Still miles from exalted...', 0, 0, '', '', '', '', '', '¿El Kirin Tor notará mi trabajo? Todavía estoy lejos de exaltado...', '', 'Кирин-Тор замечает мои усилия? До возвышения ещё далеко...'),
('suggest_faction', 'Argent Crusade needs my help, and I need their mounts!', 0, 0, '', '', '', '', '', 'La Cruzada Argenta necesita mi ayuda, ¡y yo necesito sus monturas!', '', 'Серебряный Авангард нуждается в моей помощи, а я — в их маунтах!'),
('suggest_faction', 'How do the Sons of Hodir even measure rep? I gave them a mammoth yesterday.', 0, 0, '', '', '', '', '', '¿Cómo miden la reputación los Hijos de Hodir? Ayer les di un mamut.', '', 'Как Сыны Ходира вообще измеряют репу? Вчера подарил им мамонта.'),
('suggest_faction', 'Exalted with Cenarion Expedition? More like the plant police.', 0, 0, '', '', '', '', '', '¿Exaltado con la Expedición Cenarion? Más bien la policía de las plantas.', '', 'Возвышение с экспедицией Ценариона? Больше похоже на растительную полицию.'),
('suggest_faction', 'The Ebon Blade scares me. But I need their gear.', 0, 0, '', '', '', '', '', 'La Espada de Ébano me da miedo. Pero necesito su equipo.', '', 'Эбеновый Клинок пугает меня. Но их шмот мне нужен.'),
('suggest_faction', 'How does one farm Wyrmrest rep without angering dragons?', 0, 0, '', '', '', '', '', '¿Cómo se farmea reputación con Reposo del Dragón sin enfadar a los dragones?', '', 'Как фармить репу с Драконьим Покровом, не зля драконов?'),
('suggest_faction', 'I think I offended the Oracles. They won\'t drop eggs for me anymore.', 0, 0, '', '', '', '', '', 'Creo que ofendí a los Oráculos. Ya no me dan huevos.', '', 'Кажется, я обидел Оракулов. Они больше не дают мне яйца.'),
('suggest_faction', 'Why is there no rep for killing murlocs? Seems unfair.', 0, 0, '', '', '', '', '', '¿Por qué no hay reputación por matar múrlocs? Parece injusto.', '', 'Почему за убийство мурлоков не дают репу? Несправедливо.'),
('suggest_faction', 'I need exalted with the Kalu\'ak. Their penguins are adorable.', 0, 0, '', '', '', '', '', 'Necesito exaltado con los Kaluak. Sus pingüinos son adorables.', '', 'Мне нужно возвышение с Калууак. Их пингвины восхитительны.'),
('suggest_faction', 'Knights of the Ebon Blade? More like the edgelords of Icecrown.', 0, 0, '', '', '', '', '', 'Caballeros de la Espada de Ébano? Más como los señores oscuros de Corona de Hielo.', '', 'Рыцари Эбенового Клинка? Скорее, властители льдов.'),
('suggest_faction', 'Is there a trick to speeding up the grind for Ashen Verdict rep?', 0, 0, '', '', '', '', '', '¿Hay algún truco para acelerar la reputación con el Veredicto Cinéreo?', '', 'Есть ли лайфхак, чтобы быстрее фармить репу с Пепельным Советником?'),
('suggest_faction', 'Who needs Alliance Vanguard rep? I thought we were already buddies.', 0, 0, '', '', '', '', '', '¿Quién necesita reputación con la Vanguardia de la Alianza? Creía que ya éramos amigos.', '', 'Кому нужна репа с Авангардом Альянса? Разве мы не друзья?'),
('suggest_faction', 'Why do all factions want my gold AND my time?', 0, 0, '', '', '', '', '', '¿Por qué todas las facciones quieren mi oro y mi tiempo?', '', 'Почему всем фракциям нужны и мои деньги, и моё время?'),
('suggest_faction', 'Farming rep is my cardio.', 0, 0, '', '', '', '', '', 'Farmiando reputación es mi cardio.', '', 'Фарм репы — это мой фитнес.'),
('suggest_faction', 'At this point, I\'m just farming for the shiny tabard.', 0, 0, '', '', '', '', '', 'A estas alturas, solo estoy farmeando por la tabardo brillante.', '', 'На этом этапе я фармлю только ради красивой накидки.'),
('suggest_faction', 'I could\'ve sworn I was exalted with these guys last week.', 0, 0, '', '', '', '', '', 'Podría jurar que ya estaba exaltado con estos tipos la semana pasada.', '', 'Я же клялся, что был возвышен с ними на прошлой неделе.'),
('suggest_faction', 'How is it that I\'m neutral after saving their village twice?', 0, 0, '', '', '', '', '', '¿Cómo es posible que esté neutral después de salvar su aldea dos veces?', '', 'Как так получилось, что я нейтрален, спасая их деревню дважды?'),
('suggest_faction', 'Does anyone else find rep farming oddly satisfying?', 0, 0, '', '', '', '', '', '¿Alguien más encuentra el farmeo de reputación extrañamente satisfactorio?', '', 'Кому-то ещё доставляет удовольствие фарм репы?'),
('suggest_faction', 'Rep grind = less sleep.', 0, 0, '', '', '', '', '', 'Farmear reputación = menos sueño.', '', 'Фарм репы = меньше сна.'),
('suggest_faction', 'Is it worth it for the title? Asking for a friend.', 0, 0, '', '', '', '', '', '¿Vale la pena por el título? Pregunto para un amigo.', '', 'Это стоит титула? Спрашиваю за друга.'),
('suggest_faction', 'I can\'t believe I\'m farming rep for a 10-year-old mount.', 0, 0, '', '', '', '', '', 'No puedo creer que estoy farmeando reputación por una montura de hace 10 años.', '', 'Не могу поверить, что фармлю репу ради маунта 10-летней давности.'),
('suggest_faction', 'What\'s the best way to grind rep for %faction?', 0, 0, '', '', '', '', '', '¿Cuál es la mejor forma de farmear reputación con %faction?', '', 'Как лучший способ фармить репу с %faction?'),
('suggest_faction', 'Anyone wanna form a %faction farming group?', 0, 0, '', '', '', '', '', '¿Alguien quiere formar un grupo para farmear %faction?', '', 'Кто хочет создать группу для фарма %faction?'),
('suggest_faction', 'LFM %faction rep grind. Need DPS.', 0, 0, '', '', '', '', '', 'Busco grupo para %faction. Se necesita DPS.', '', 'Ищу группу для фарма %faction. Нужен ДД.'),
('suggest_faction', 'How long does it take to hit exalted with %faction?', 0, 0, '', '', '', '', '', '¿Cuánto tiempo toma llegar a exaltado con %faction?', '', 'Сколько времени нужно, чтобы стать возвышенным с %faction?'),
('suggest_faction', 'Is %faction gear any good for %my_class?', 0, 0, '', '', '', '', '', '¿Es buena la armadura de %faction para %my_class?', '', 'Экипировка %faction полезна для %my_class?'),
('suggest_faction', 'Does anyone have quests for %faction they can share?', 0, 0, '', '', '', '', '', '¿Alguien tiene misiones de %faction para compartir?', '', 'У кого есть квесты для %faction, которые можно поделиться?'),
('suggest_faction', 'Can you solo farm %faction rep? Asking for a squishy DPS.', 0, 0, '', '', '', '', '', '¿Se puede farmear reputación de %faction solo? Pregunto por un DPS blandito.', '', 'Можно ли фармить репу с %faction в одиночку? Спрашиваю за мягкого ДД.'),
('suggest_faction', 'If I farm any more for the Argent Crusade, they better name a horse after me.', 0, 0, '', '', '', '', '', 'Si farmeo más para la Cruzada Argenta, deberían nombrar un caballo en mi honor.', '', 'Если я еще раз пофармлю для Серебряного Авангарда, пусть назовут лошадь в мою честь.'),
('suggest_faction', 'Does anyone else think the Frenzyheart Tribe is just misunderstood?', 0, 0, '', '', '', '', '', '¿Alguien más piensa que la Tribu Corazón Frenético está incomprendida?', '', 'Кто-нибудь еще думает, что племя Буйного Сердца просто недопонято?'),
('suggest_faction', 'Why do the Oracles give eggs? Are they chickens or prophets?', 0, 0, '', '', '', '', '', '¿Por qué los Oráculos dan huevos? ¿Son gallinas o profetas?', '', 'Почему Оракулы дают яйца? Они что, куры или пророки?'),
('suggest_faction', 'Do you think the Kirin Tor ever take a day off? Asking for my mana.', 0, 0, '', '', '', '', '', '¿Crees que el Kirin Tor alguna vez se toma un día libre? Pregunto por mi maná.', '', 'Кирин-Тор когда-нибудь отдыхают? Спрашиваю ради своей маны.'),
('suggest_faction', 'Wyrmrest Accord makes me nervous. I mean, dragons.', 0, 0, '', '', '', '', '', 'Reposo del Dragón me pone nervioso. Quiero decir, dragones.', '', 'Драконий Пакт меня пугает. Ну вы поняли, драконы.'),
('suggest_faction', 'The Kalu\'ak fishing poles are legendary. Totally worth the grind.', 0, 0, '', '', '', '', '', 'Las cañas de pescar de los Kalu\'ak son legendarias. Totalmente valen el esfuerzo.', '', 'Удочки Калуу\'ак — это легенда. Стоит фарма.'),
('suggest_faction', 'Is Hodir really a nice guy? Feels like he just wants my relics.', 0, 0, '', '', '', '', '', '¿Hodir realmente es un buen tipo? Parece que solo quiere mis reliquias.', '', 'Ходир правда хороший парень? Кажется, он хочет только мои реликвии.'),
('suggest_faction', 'If I hear one more Murloc while farming, I\'m switching factions.', 0, 0, '', '', '', '', '', 'Si escucho un múrloc más mientras farmeo, cambio de facción.', '', 'Если я услышу еще одного мурлока во время фарма, я сменю фракцию.'),
('suggest_faction', 'Grind harder, they said. Exalted is worth it, they said.', 0, 0, '', '', '', '', '', 'Farmea más duro, dijeron. Ser exaltado vale la pena, dijeron.', '', 'Фармить усерднее, говорили они. Возвышение стоит того, говорили они.'),
('suggest_faction', 'Farming %faction. Anyone wanna join me for some company?', 0, 0, '', '', '', '', '', 'Farmeando %faction. ¿Alguien quiere unirse para hacerme compañía?', '', 'Фармлю %faction. Кто хочет присоединиться для компании?'),
('suggest_faction', 'I could use a partner for this rep grind. %faction is exhausting.', 0, 0, '', '', '', '', '', 'Podría usar un compañero para este farmeo. %faction es agotador.', '', 'Мне нужен напарник для этого фарма. %faction выматывает.'),
('suggest_faction', 'Can you really be exalted with everyone? My bags are full of junk already.', 0, 0, '', '', '', '', '', '¿Realmente puedes estar exaltado con todos? Mis bolsas ya están llenas de porquerías.', '', 'Можно ли возвыситься со всеми? У меня уже всё завалено хламом.'),
('suggest_faction', 'Why does %faction feel harder than any raid boss?', 0, 0, '', '', '', '', '', '¿Por qué %faction parece más difícil que cualquier jefe de banda?', '', 'Почему %faction сложнее любого босса рейда?'),
('suggest_faction', 'What do you think? %faction or %other_faction first?', 0, 0, '', '', '', '', '', '¿Qué piensas? ¿%faction o %otra_facción primero?', '', 'Как думаешь, %faction или %other_faction сначала?'),
('suggest_faction', 'Do you ever feel like NPCs judge you when you\'re not exalted?', 0, 0, '', '', '', '', '', '¿Alguna vez sientes que los NPC te juzgan cuando no eres exaltado?', '', 'Чувствуешь ли ты, что НПС судят тебя, если ты не возвышен?'),
('suggest_faction', 'Can anyone share a shortcut for %faction grind? Please.', 0, 0, '', '', '', '', '', '¿Alguien puede compartir un atajo para farmear %faction? Por favor.', '', 'Может кто-то знает лайфхак для фарма %faction? Пожалуйста.'),
('suggest_faction', 'You\'d think %faction would love me after 100 quests. Nope.', 0, 0, '', '', '', '', '', 'Uno pensaría que %faction te querría después de 100 misiones. Pues no.', '', 'Казалось бы, %faction полюбят меня после 100 квестов. Нет.'),
('suggest_faction', 'One more dungeon run and I\'m exalted. Who\'s with me?', 0, 0, '', '', '', '', '', 'Una mazmorra más y estoy exaltado. ¿Quién se apunta?', '', 'Ещё один поход в подземелье, и я возвышен. Кто со мной?'),
('suggest_faction', 'When you\'re exalted with %faction, do they throw a party?', 0, 0, '', '', '', '', '', 'Cuando eres exaltado con %faction, ¿hacen una fiesta?', '', 'Когда ты возвышен с %faction, они устраивают вечеринку?'),
('suggest_faction', 'I hear %faction has the best tabards. True?', 0, 0, '', '', '', '', '', 'Escuché que %faction tiene los mejores tabardos. ¿Es cierto?', '', 'Говорят, у %faction лучшие накидки. Это правда?'),
('suggest_faction', 'Why does %faction gear look like it was made by goblins?', 0, 0, '', '', '', '', '', '¿Por qué el equipo de %faction parece hecho por goblins?', '', 'Почему снаряжение %faction выглядит так, как будто его сделали гоблины?'),
('suggest_faction', 'Anyone need the %faction mount? I\'m going for it.', 0, 0, '', '', '', '', '', '¿Alguien necesita la montura de %faction? Yo voy por ella.', '', 'Кому нужна маунт %faction? Я иду за ним.'),
('suggest_faction', 'The questline for %faction is great, but these drop rates? Yikes.', 0, 0, '', '', '', '', '', 'La línea de misiones de %faction es genial, pero estas tasas de caída... Ay.', '', 'Квестовая цепочка %faction отличная, но шансы выпадения? Жуть.'),
('suggest_faction', 'If %faction didn\'t have good rewards, would anyone farm it?', 0, 0, '', '', '', '', '', 'Si %faction no tuviera buenas recompensas, ¿alguien lo farmearía?', '', 'Если бы у %faction не было наград, кто-нибудь бы фармил это?'),
('suggest_faction', 'Does %faction rep come with a side of frustration? Asking for a friend.', 0, 0, '', '', '', '', '', '¿La reputación de %faction viene con una dosis de frustración? Pregunto para un amigo.', '', 'Фракционная репутация %faction поставляется с дозой разочарования?'),
('suggest_faction', 'If farming %faction isn\'t bad enough, now there\'s competition for mobs.', 0, 0, '', '', '', '', '', 'Si farmeando %faction no era suficiente, ahora hay competencia por los mobs.', '', 'Если фарм %faction ещё не был достаточно сложным, теперь конкуренция за мобов.'),
('suggest_faction', 'I heard %faction likes gifts. What should I bring?', 0, 0, '', '', '', '', '', 'Escuché que a %faction les gustan los regalos. ¿Qué llevo?', '', 'Слышал, %faction любят подарки. Что принести?');
INSERT INTO `ai_playerbot_texts` (`name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
