('suggest_something', 'Why are all epic items purple? What\'s wrong with gold?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I threw a fish at someone in Stormwind once. They logged out.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do Tauren use their horns to hang stuff? Asking for a friend.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I think I saw a goblin eating gunpowder. Is that normal?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I tried to eat a mana biscuit. It was crunchy. Too crunchy.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I wonder if worgen bark in their sleep. Or howl?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Dwarves in Ironforge drink so much, I swear the air there is alcoholic.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I saw a druid casting heals while in bear form. Multi-talented.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'How do ogres even fit into their own camps? They\'re huge!', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Every time I see a blood elf, I feel like I\'m being judged.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Who decided murlocs needed to scream like banshees? Was it necessary?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I swear I saw a gnome trying to train a squirrel as a pet.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Does anyone else hoard useless grey items because they\'re “funny”?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I\'m convinced goblins use explosions to greet each other.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Old Gods probably think we\'re just ants running around.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I saw a mage polymorph a rogue. Pretty sure the rogue ragequit.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Why does everything in Outland float? Is gravity optional?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I think my hunter\'s pet hates me. It keeps growling.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Draenei hooves must be tough to clean. How do they even do it?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do you think mages ever misclick and teleport to the wrong city?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Why do undead still wear shoes? Do they even need them?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do gnomes ever fall into their own engineering gadgets by mistake?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Once saw a paladin bubble themselves and just...stand there.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I saw a night elf dancing on a mailbox for gold. Classic.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Every time I visit Northrend, I feel like something\'s watching me.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Why does every troll seem like they just woke up from a nap?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do Forsaken still celebrate birthdays? How does that even work?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I swear that random NPC in Booty Bay winked at me.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Every time I queue for a dungeon, I question my life choices.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Why do mages need portals when they can blink everywhere?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if goblins invented fel magic but forgot to patent it?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do dragons have a favorite element? Or do they argue over which is best?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Once found a squirrel riding a mechanical chicken. Thought I was hallucinating.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do ogres ever wonder why they only have two heads sometimes?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Why does Dalaran have no bathrooms? It\'s a city of wizards!', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I saw a rogue pickpocket a fish. How does that even work?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'If the Exodar had a horn, I bet it would play the “sad trombone” sound.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Why does every druid insist their cat form is better? They\'re all the same.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Once saw a dwarf duel a keg. The keg won.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Why does every blacksmith in Azeroth sound grumpy? Must be the forge.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do demons have favorite snacks? I feel like it\'s probably spicy.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Does anyone else collect junk for fun? My bags are full.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I swear I saw a skeleton waving at me in Scholomance.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Is it just me, or do mana wyrms seem way too smug?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Every time I hearthstone, I half expect it to explode.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Once saw a goblin sell “used dynamite.” Who buys that?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Every time I pass through Duskwood, I hear whispers. Do you hear them too?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I swear the statues in Karazhan move when you\'re not looking.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if the Old Gods never really died? What if they\'re just watching us?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Does anyone else feel like Icecrown has...a heartbeat?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'They say Arthas\'s voice still echoes in the halls of Icecrown Citadel.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Forsaken don\'t sleep, but do they dream?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I saw a shadow in Deadwind Pass that didn\'t match anything around me.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Why is there always blood in Scholomance? It never seems to dry.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I once touched a fel crystal. My hand still burns in the cold.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if Deathwing didn\'t go insane? What if he saw something we can\'t?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'There\'s a grave in Tirisfal that doesn\'t have a name. Just a warning.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Twilight\'s Hammer didn\'t vanish. They\'re waiting.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I heard the Scarlet Crusade still operates in secret. How do you kill what\'s already zealot-dead?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Sometimes I see faces in the shadows of Naxxramas. Faces I recognize.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do you think the Lich King wanted us to take Frostmourne? Maybe it wasn\'t a mistake.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The deeper you go into the Emerald Nightmare, the harder it is to leave.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What\'s buried beneath Tirisfal Glades? Nobody seems to know.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I saw a broken sword in Stratholme. The blade still whispers.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'They say dragons can\'t die forever. But what happens to their spirits?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if Azeroth\'s core isn\'t just molten rock? What if it\'s...alive?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'There\'s a sunken ship off the coast of Tanaris. Sometimes, it looks...new.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Ethereals aren\'t just traders. They\'re hiding something bigger.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Scourge didn\'t crumble when the Lich King died. It just...waited.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I heard a story about a mage who went to Dalaran and never came back. Just...vanished.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Why do the Naaru oscillate between light and void? It\'s not natural.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I saw a troll witchdoctor once. His eyes glowed like he\'d seen death itself.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The spirits in Ghostlands aren\'t just restless. They\'re angry.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Ever notice how the Worgen curse seems to linger, even after it\'s cured?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I think the sands of Silithus move on their own. Like they\'re alive.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'A blood elf once told me they saw Kael\'thas\'s ghost in Silvermoon.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I once heard footsteps behind me in the Plaguelands. But nobody was there.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'There\'s something in the Well of Eternity. Something looking back at us.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'How do we know we actually killed Yogg-Saron? It could just be hiding.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The sun doesn\'t shine the same way in Icecrown. It\'s...dimmer.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I found an old tome in Stratholme. The pages screamed when I opened it.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Ever notice how dead things in the Shadowlands seem to remember us?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The statues in Stormwind have cracks. Like something\'s trying to get out.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Sometimes when you fish in Duskwood, you pull up...pieces.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The void doesn\'t just whisper. Sometimes, it screams.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if Azeroth itself doesn\'t want us here?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Scarlet Crusade isn\'t as gone as we think. I\'ve seen their banners.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do you think the Light is actually watching us? Or is it just...gone?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Every time I hearthstone, I swear it pulls something out of me.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The void doesn\'t lie. It just shows you what you\'re afraid of.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Ever wonder what\'s really under the Dark Portal?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Emerald Dream isn\'t as peaceful as it looks. I\'ve seen nightmares there.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if the Titans didn\'t build Azeroth? What if they just found it?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Every time I use a portal, I feel like something follows me through.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if the whispers of the Old Gods never leave us? What if they\'re still here?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'In Northrend, the ice sometimes hums. Like it\'s...alive.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I swear I saw someone in my reflection while fishing in Darkshore.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do Forsaken remember their deaths, or just the pain?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I heard someone laughing in Icecrown. Nobody else was there.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The sky over Silithus looks wrong. Like it\'s been...torn.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'There\'s a grave in the Plaguelands that glows at night. Nobody knows why.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Void doesn\'t offer answers. It offers truths we\'re not ready for.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Why do the ghosts in Deadwind Pass whisper names? I heard mine once.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Have you noticed how quiet it gets near the Dark Portal? Too quiet.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do demons fear anything? What terrifies something that can\'t die?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I think the Fel leaves scars we can\'t see.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Sometimes when I fish in Azshara, I pull up bones. Small ones.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I swear I saw Deathwing\'s shadow pass over Orgrimmar last week.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The deeper you go into Blackrock Mountain, the hotter the walls seem to breathe.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I heard the druids in the Emerald Dream can\'t tell what\'s real anymore.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'If you stare into the Well of Eternity too long, it stares back.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I saw a blood elf in Silvermoon crying. Said they could still hear Kael\'thas.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Shadowlands feel too familiar. Like we\'ve been there before.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The runes on Frostmourne still burn in my dreams.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Zandalari priests talk about the Loa like they\'re watching us...always.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'There\'s a crypt in Duskwood with no entrance. But people swear they hear voices inside.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I heard a story about someone who walked into Stratholme and never came out. The bell still rings.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Ever notice how the sky over Icecrown never changes? It\'s like time\'s frozen there.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Black Temple still feels...tainted. Like it remembers Illidan.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Twilight Highlands feel like they\'re waiting for something. Something worse.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'In Felwood, I saw trees move when there was no wind.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The undead in Tirisfal don\'t attack me anymore. It\'s like they recognize me.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Ever hear the screaming in Shadowmoon Valley? It\'s faint, but it\'s there.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'There\'s a cavern in Deepholm where the rocks hum. It\'s not natural.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Scourge didn\'t disappear. They just wait for the right call.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I saw something in the Maelstrom. Something with eyes.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do you think Azeroth feels every wound we cause her?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'There\'s something wrong with Draenor. The light there doesn\'t feel right.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Ever notice how the bones in Desolace don\'t look like they belong to anything alive?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Sometimes in Silverpine Forest, I hear wolves howl in a voice too...human.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if the Burning Legion never stopped watching us?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The wailing caverns don\'t just wail. If you listen closely, you hear words.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Ever stand in Ulduar and feel...small? Like something\'s watching you?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I found a book in Undercity. The words rearranged themselves when I tried to read it.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'There\'s a hole in Darkshore that wasn\'t there before. It breathes.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do the Naaru really care about us? Or are we just tools for their war?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Sometimes in Zangarmarsh, I hear the mushrooms hum.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'In Arathi Highlands, there\'s a stone circle that feels...wrong.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'The Legion left scars on Azeroth that won\'t ever heal.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if the Titans aren\'t coming back? What if they abandoned us?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'There\'s a tomb in Shadowmoon Valley that glows at night. Nobody knows why.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do you think Thrall likes to “shaman slam”?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'You can “ignite” my combustion anytime, mage.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Careful with that polearm... you might poke someone.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I heard gnomes really know how to tinker... if you know what I mean.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Mind if I inspect your gear? Thoroughly.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I\'ve got a “dagger” that\'s fast and precise. Wanna see?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Are you a succubus? Because you\'ve got me... enthralled.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Let\'s take this to my garrison... for some “private quests.”', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Is that a mace, or are you just happy to see me?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Let me see your talents. All of them.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I\'m specced into dual-wield... ready for action.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Are you a rogue? Because you just pick-pocketed my heart.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I heard dwarves like to “forge bonds” over a good ale.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'My hearthstone isn\'t the only thing that\'s hot tonight.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Wanna form a two-man dungeon team? Just you and me.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I\'ll be your tank if you promise to keep me... topped off.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Let\'s check your stamina pool... repeatedly.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I hear the Exodar has amazing “light shows.” Care to visit?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I see you\'ve been grinding rep... mind if I “join the grind?”', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'You must be a demon hunter... because you\'ve got me seeing stars.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Wanna share a hearthstone? Things could get cozy.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I\'m enchanted by your looks. Literally... you must be a caster.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Careful, I might “pull aggro” if you keep looking at me like that.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I promise not to “roll need”... unless it\'s for you.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'You\'re like a rare drop—impossible to find and worth the grind.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Are we in Alterac Valley? Because sparks are flying.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Let\'s cast “time warp” and make this last all night.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I\'m a frost mage, but I can get you all hot and bothered.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I\'d go to the Nether and back just for you.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'You\'re more stunning than a chain lightning crit.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Let\'s “combine forces” like the elements... and make magic.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'You must be a druid, because you\'re leaving me spellbound.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I\'d let you “roll need” on my heart anytime.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'You\'ve got me rooted... but I don\'t want to break free.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Want to come back to my campfire and... chat?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'That armor looks nice... on the floor.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Are you a warlock? Because you\'ve got me enslaved.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do you want to “queue up”... for some fun?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'You\'re a raid boss, and I\'m ready to “pull.”', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'That\'s some serious DPS you\'ve got there.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I\'ll be your escort quest any day.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do you want to “explore” my dungeon?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'You must have a high charisma stat... because I\'m captivated.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'You\'ve disarmed me... and not just my weapon.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I see we\'ve got some good synergy... let\'s put it to use.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Your gear score might be high, but I\'m looking at your “natural talents.”', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Remember that one time Onyxia invaded Stormwind and kidnapped Prince Anduin? Good times... Gooood times.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Wonder what Outlands looked like before it was Outlands... sucks we\'ll never get to see it.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do you think the Lich King\'s helmet is connected to anything? It\'s got to be old, right? Wonder how fragile it is.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Anyone know what Neltherian is up to? Hope he\'s doing okay.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'I wonder if the negative emotes we have affect anything in the world... imagine overturning a whole civilization with /rude.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Hey guys, what if we turned the Dark Portal into a time machine?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'If I had a silver for every time the Legion invaded Azeroth, I\'d have 1 silver. Not much, but it\'d be weird if it happened twice.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Almost yelled “Burn it!” in Teldrassil. Glad I kept that to myself.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if the afterlife was just a bunch of puppets? That\'d be CRAZY.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Had a dream they let these weird lizards join the Horde and Alliance. Good thing that doesn\'t exist... Right?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if some lady tried to take over Azeroth... but didn\'t wear shoes? Someone should write that story.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'If the Bronze Dragonflight ever gets bored, maybe they could open a theme park.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Anyone else wonder if Azeroth is just one big Titan terrarium?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Do murlocs ever wonder why we keep attacking them? Poor little gurgly guys.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if Sylvanas had a redemption arc, but she just kept the crazy eyes?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Does anyone else think all these ancient weapons we\'re finding are just Titan hand-me-downs?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if Gallywix opened a casino instead of doing... whatever he\'s doing now?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Had a weird dream last night: the Horde and Alliance went to space. Someone stop the Bronze Dragonflight.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'What if the Light and Void are just two old gods bickering over nothing?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something', 'Almost ran a dungeon with Thrall once. Turns out it was just some guy RPing.', 0, 0, '', '', '', '', '', '', '', '');
INSERT INTO `ai_playerbot_texts` (`name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
('suggest_something_toxic', 'what is ligma', 0, 0, '', '', '', '', '', '', '', ''),
