('reply', '%s ill vomit into your fkin mouth', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'dont fucking judge me', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Yo momma so fat, she cant even fit through the Dark Portal', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'I\'m coming for you, %s. This time, no mercy.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Better sleep with one eye open, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Next time I see you, %s, you\'ll regret it.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, your days are numbered.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Youre nothing but an Alliance dog, %s!', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Keep talking, %s. I\'ll shut you up for good.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, Im gonna bury you in Westfall.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Mark my words, %s, you\'ll pay for that.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You think you\'re clever, %s? Just wait.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Prepare to eat dirt, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Yo, %s, even Hogger fights better than you.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Next time, %s, bring your A-game. Or at least your B-game.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'By the Light, %s, you fight like a kobold with no candle.', 0, 1, '', '', '', '', '', '', '', ''),
