('reply', 'I\'m about to drop you harder than Deathwing dropped Stormwind, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, youll need more than healing potions to survive me.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Your time\'s up, %s. Meet me in the Shadowlands.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, even the Naaru can\'t save you now.', 0, 1, '', '', '', '', '', '', '', ''),
