('reply', 'Youre about as threatening as a neutral critter, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, Ive seen sharper strategy from Defias thugs.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Youre all bark and no bite, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Keep trying, %s. Maybe one day youll reach murloc level.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, you\'d trip over your own feet in a duel.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Is that the best insult you learned in Booty Bay, %s?', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, even the Scarlet Crusade would laugh at you.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re as scary as a mechanical squirrel, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'I\'ve seen more intimidating gnomes than you, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'By the Earthmother, %s, your reckoning is near.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, I\'ll smash you into the dirt like a kodo in a stampede.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'The ancestors won\'t save you this time, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You crossed the wrong adventurer, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Prepare to taste steel, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, I\'ll leave you begging for a spirit healer.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re going down faster than a Horde raid on Alliance turf, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Your doom approaches, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'The Light won\'t save you, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'I\'m about to turn you into quest loot, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'This isn\'t over, %s. Not by a long shot.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ll regret crossing me, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Enjoy your victory, %s. It won\'t last.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'I\'ll haunt you across Azeroth, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Next time, %s, I\'ll bury you so deep even the Undercity won\'t take you.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'By the ancestors, %s, I will have my revenge.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, you\'re more annoying than Defias bandits in the Deadmines.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ll be begging for a spirit healer soon, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'I\'ll carve your name into the stones of Mulgore as a warning, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ve made a grave mistake, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Careful, %s, or I\'ll report you to Hogger.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, I\'ll send you back to the starting zone!', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re about to feel the wrath of a well-fed Pandaren, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Better run, %s, because I\'m pulling all the mobs your way.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re toast, %s. Burnt like Dark Iron bread.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, I\'ll drop you faster than Deathwing dropped the world.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re not even a worthy loot drop, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Keep it up, %s, and I\'ll kite you into an elite spawn.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'I\'ve seen murlocs fight better than you, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re about as dangerous as a critter, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Is that all you\'ve got, %s?', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Nice try, %s. Better luck next time.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, you\'re about as scary as a fluffy Talbuk.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Was that supposed to hurt, %s? I barely felt it.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, I\'ve faced tougher gnolls in Elwynn Forest.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Keep dreaming, %s. Maybe one day you\'ll hit me.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, you fight like a gnome trying to use a two-hander.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Even goblins wouldn\'t take you seriously, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, you\'re more of a nuisance than a threat.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Oh, %s, you\'re really giving it your all, aren\'t you?', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ve earned my wrath, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'I\'ll see you in the battlegrounds, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'By Elune, %s, your time has come.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'I\'ll make sure the spirit healer knows your name, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Your name will be forgotten in the sands of Tanaris, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re about to learn why the Horde fears me, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, you\'ve made your last mistake.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Prepare to taste defeat, %s. And it\'ll be bitter.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ve awakened something dark, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You won\'t make it out of %zone_name alive, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'By the Sunwell, %s, you\'ve chosen poorly.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, I\'ll see you on the other side of the Dark Portal.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'The ancestors frown upon your actions, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ve drawn the ire of the spirits, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'May the Light have mercy on your soul, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Even the Naaru can\'t save you from me, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'The tides of battle will sweep you away, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Your deeds will be undone, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'By the Bronze Dragonflight, %s, your time has run out.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ve angered the wrong adventurer, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Careful, %s. You\'re playing with fire.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Next time, %s, try hitting me harder.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, you\'re about as effective as a broken fishing rod.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You call that an attack, %s? My grandma hits harder.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', '%s, you couldn\'t hit the broadside of a kodo.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Keep trying, %s. Maybe one day you\'ll land a real hit.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re funnier than a drunk dwarf, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Don\'t quit your day job, %s. Fighting isn\'t your thing.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re as threatening as a baby murloc, %s.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Is that all you\'ve got, %s? Pathetic.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re like a voidwalker—empty, slow, and nobody really wants you around.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Bold words for someone who rolls need on greens.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Keep talking, %s. The mobs find you as annoying as I do.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Are you trying to tank the conversation too? Because you\'re losing aggro.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Your life must be like a rogue\'s vanish: full of sudden disappointments.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You talk a lot for someone who stands in fire.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re proof that RNG doesn\'t favor intelligence.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Talking to you is like looting gray items—pointless.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ve got less presence than a hunter\'s pet on passive.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Your insults hit like a level 1 spell—weak and unimpressive.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'If your IQ were crit chance, we\'d never see a big number.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re like an escort quest—slow, frustrating, and nobody wants to deal with you.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Bold move for someone whose entire build is just bad decisions.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ve got the charm of a gnome warrior and the wit of a broken goblin shredder.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'If you were loot, I\'d disenchant you for mats.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re the kind of player who queues DPS and thinks they\'re the main character.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'I\'d roast you, but I\'m afraid it\'d pull aggro on the entire raid.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ve got more drama than a Silvermoon City tavern.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Did you respec into “annoying,” or is it just natural talent?', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You talk a big game for someone who probably keyboard turns.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Your flirting is about as effective as a level 5 spell on a raid boss.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'I bet your macros are as basic as your personality.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re the kind of person who face-pulls and blames the tank.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Your insults land about as well as a poorly placed frost trap.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ve got the strategic brilliance of a paladin charging into a lava pool.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Your trash talk is like low-level loot: nobody\'s picking it up.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ve got the energy of someone who uses all-caps to whisper.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'If you were any more clueless, you\'d be an NPC giving out bad quests.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'I\'d duel you, but I left my patience in the repair shop.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'d lose an argument to a murloc with a speech impediment.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Your sense of humor must\'ve been nerfed in the last patch.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Talking to you is like leveling fishing—time-consuming and unrewarding.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'If charisma were a stat, yours would have a negative modifier.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ve got the vibe of someone who equips strength gear as a mage.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'If you were any less interesting, you\'d be a stockpile of gray items.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Your jokes are as stale as Darnassus.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'d make a great stealth build—nobody notices you anyway.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re so petty, even the Black Market Auction House wouldn\'t deal with you.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'If cringe were a debuff, you\'d be perma-stunned.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Your energy screams “AFK in a battleground.”', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ve got the emotional range of a neutral NPC.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Even a goblin wouldn\'t bet on you.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re like world PvP—unwelcome and annoying.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'ve got the charm of a death knight in a romance novel.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'If embarrassment were a buff, you\'d be stacking it.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'Even a hunter pet has more loyalty than you.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re the kind of person who ninja loots and writes an apology letter.', 0, 1, '', '', '', '', '', '', '', ''),
('reply', 'You\'re as trustworthy as a goblin banker during a market crash.', 0, 1, '', '', '', '', '', '', '', '');
