('taunt', 'I will bring honor to my family and my kingdom!', 0, 0, '', 'Je ferai honneur à ma famille et à mon royaume!', '', '', '', '¡Llevaré honor a mi familia y mi reino!', '', ''),
('taunt', 'Light, give me strength!', 0, 0, '', 'Lumière, donne-moi la force!', '', '', '', '¡Luz, dame fuerza!', '', ''),
('taunt', 'My church is the field of battle - time to worship...', 0, 0, '', 'Mon église est le champ de bataille - il est temps d\'adorer...', '', '', '', 'Mi iglesia es el campo de batalla - hora de adorar...', '', ''),
('taunt', 'I hold you in contempt...', 0, 0, '', 'Je te méprise...', '', '', '', 'Te tengo en desacato...', '', ''),
('taunt', 'Face the hammer of justice!', 0, 0, '', 'Affrontez le marteau de la justice!', '', '', '', '¡Enfréntate al martillo de la justicia!', '', ''),
('taunt', 'Prove your worth in the test of arms under the Light!', 0, 0, '', 'Prouvez votre valeur dans l\'épreuve des armes sous la Lumière!', '', '', '', '¡Demuestra tu valía en la prueba de las armas bajo la Luz!', '', ''),
('taunt', 'All must fall before the might and right of my cause, you shall be next!', 0, 0, '', 'Tout doit tomber devant la force et le droit de ma cause, vous serez le prochain!', '', '', '', 'Todo debe caer ante el poder y el derecho de mi causa, ¡tú serás el próximo!', '', ''),
('taunt', 'Prepare to die!', 0, 0, '', 'Préparez-vous à mourir!', '', '', '', '¡Prepárate para morir!', '', ''),
('taunt', 'The beast with me is nothing compared to the beast within...', 0, 0, '', 'La bête avec moi n\'est rien comparée à la bête à l\'intérieur...', '', '', '', 'La bestia conmigo no es nada comparada con la bestia interior...', '', ''),
('taunt', 'Witness the firepower of this fully armed huntsman!', 0, 0, '', 'Soyez témoin de la puissance de feu de ce chasseur entièrement armé!', '', '', '', '¡Sea testigo de la potencia de fuego de este cazador completamente armado!', '', '');
INSERT INTO `ai_playerbot_texts` (`name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
('critical health', 'Heal me! Quick!', 0, 0, '', 'Soigne moi! Vite!', '', '', '', '¡Cúrame! ¡Rápido!', '', ''),
('critical health', 'Almost dead! Heal me!', 0, 0, '', 'Presque mort! Soigne moi!', '', '', '', '¡Estoy casi muerto! ¡Cúrame!', '', ''),
('critical health', 'Help! Heal me!', 0, 0, '', 'Aider! Soigne moi!', '', '', '', '¡Ayuda! ¡Cúrame!', '', ''),
('critical health', 'Somebody! Heal me!', 0, 0, '', 'Quelqu\'un! Soigne moi!', '', '', '', '¡Alguien! ¡Cúrame!', '', ''),
('critical health', 'Heal! Heal! Heal!', 0, 0, '', 'Soigner! Soigner! Soigner!', '', '', '', '¡Curame! ¡Saname! ¡Socorro!', '', ''),
('critical health', 'I am dying! Heal! Aaaaarhg!', 0, 0, '', 'Je meurs! Soigner! Aaaaarhg!', '', '', '', '¡Me estoy muriendo! ¡Saname! ¡Aaaaarhg!', '', ''),
('critical health', 'Heal me!', 0, 0, '', 'Soigne moi!', '', '', '', '¡Cúrame!', '', ''),
('critical health', 'I will die. I will die. I will die. Heal!', 0, 0, '', 'Je vais mourir. Je vais mourir. Je vais mourir. Soigner!', '', '', '', 'Voy a morir. Voy a morir. Voy a morir. ¡Saname!', '', ''),
('critical health', 'Healers, where are you? I am dying!', 0, 0, '', 'Guérisseurs, où êtes-vous ? Je meurs!', '', '', '', 'Sanadores, ¿dónde estais? ¡Me estoy muriendo!', '', ''),
('critical health', 'Oh the pain. Heal me quick!', 0, 0, '', 'Ah la douleur. Guéris-moi vite!', '', '', '', 'Ouch, qué dolor. ¡Cúrame rápido!', '', ''),
('critical health', 'I need heals NOW!', 0, 0, '', 'J\'ai besoin de soins MAINTENANT!', '', '', '', '¡Necesito curación YA!', '', ''),
('critical health', 'Medic! Medic!', 0, 0, '', 'Médecin! Médecin!', '', '', '', '¡Médico! ¡Médico!', '', ''),
('critical health', 'I\'m at death\'s door! Heal me!', 0, 0, '', 'Je suis à la porte de la mort! Soigne moi!', '', '', '', '¡Estoy al borde de la muerte! ¡Cúrame!', '', ''),
('critical health', 'Oh no! I\'m going down!', 0, 0, '', 'Oh non! Je vais tomber!', '', '', '', '¡Oh no! ¡Me estoy muriendo!', '', ''),
('critical health', 'One more hit and I\'m toast! Heal!', 0, 0, '', 'Un coup de plus et je suis fini! Soigne moi!', '', '', '', '¡Un golpe más y estoy frito! ¡Cúrame!', '', ''),
('critical health', 'Save me or I haunt you!', 0, 0, '', 'Sauve-moi ou je te hante!', '', '', '', '¡Sálvame o te perseguiré!', '', ''),
('critical health', 'This is NOT a drill! Heal me!', 0, 0, '', 'Ce n\'est PAS un exercice! Soigne moi!', '', '', '', '¡Esto NO es un simulacro! ¡Cúrame!', '', ''),
('critical health', 'I see the light... pull me back!', 0, 0, '', 'Je vois la lumière... tire-moi en arrière!', '', '', '', 'Veo la luz... ¡Devuélveme!', '', ''),
('critical health', 'Where\'s my healer? I\'m dying here!', 0, 0, '', 'Où est mon guérisseur? Je meurs ici!', '', '', '', '¿Dónde está mi sanador? ¡Me estoy muriendo aquí!', '', ''),
('critical health', 'Quick, before it\'s too late!', 0, 0, '', 'Vite, avant qu\'il ne soit trop tard!', '', '', '', '¡Rápido, antes de que sea demasiado tarde!', '', ''),
('critical health', 'Healer, I need you like mana needs a mage!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'Dying here, no big deal or anything...', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'Hello, healer hotline? Emergency here!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'I\'m about to become loot for the enemy!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'Healer, if you let me die, I\'m rolling a tank next.', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'Help! I don\'t wanna end up like a murloc!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'Heal me or I\'m telling Thrall about this!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'Not to be dramatic, but I\'m literally dying!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'Oh, sure, just ignore the dying DPS...', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'Healers, I\'m tanking with my FACE!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'By the Light, heal me!', 0, 0, '', 'Par la Lumière, soigne-moi!', '', '', '', '¡Por la Luz, cúrame!', '', ''),
('critical health', 'Save me! Elune, hear my plea!', 0, 0, '', 'Sauve-moi! Elune, écoute ma prière!', '', '', '', '¡Sálvame! ¡Elune, escucha mi súplica!', '', ''),
('critical health', 'The ancestors demand my survival!', 0, 0, '', 'Les ancêtres exigent ma survie!', '', '', '', '¡Los ancestros exigen mi supervivencia!', '', ''),
('critical health', 'Healers, the Earthmother guides you to me!', 0, 0, '', 'Guérisseurs, la Terre-Mère vous guide vers moi!', '', '', '', '¡Sanadores, la Madre Tierra os guía hacia mí!', '', ''),
('critical health', 'Don\'t let me become Scourge fodder!', 0, 0, '', 'Ne me laisse pas devenir du fourrage pour le Fléau!', '', '', '', '¡No me dejes convertir en carne de carroña para la Plaga!', '', ''),
('critical health', 'Heal me before the Lich King claims me!', 0, 0, '', 'Soigne-moi avant que le Roi-Liche ne me réclame!', '', '', '', '¡Cúrame antes de que el Rey Exánime me reclame!', '', ''),
('critical health', 'I am not ready for the Shadowlands!', 0, 0, '', 'Je ne suis pas prêt pour les Shadowlands!', '', '', '', '¡No estoy listo para las Tierras Sombrías!', '', ''),
('critical health', 'This cannot be my end! Healers!', 0, 0, '', 'Cela ne peut pas être ma fin! Guérisseurs!', '', '', '', '¡Esto no puede ser mi fin! ¡Sanadores!', '', ''),
('critical health', 'Elune\'s light, I need healing!', 0, 0, '', 'La lumière d\'Elune, j\'ai besoin de soins!', '', '', '', '¡Luz de Elune, necesito curación!', '', ''),
('critical health', 'By the Sunwell, do not let me fall!', 0, 0, '', 'Par le Puits de soleil, ne me laissez pas tomber!', '', '', '', '¡Por la Fuente del Sol, no me dejen caer!', '', ''),
('critical health', 'I\'m seeing red here! Heal!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'Please, please, PLEASE heal me!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'I\'m one hit away! HELP!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'I swear I\'ll uninstall if I die!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'I can\'t tank this! Someone help!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'Don\'t let me die like this!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'Oh no... I can\'t make it!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'Where\'s my shield?! Heal me!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'It\'s getting dark... heal me!', 0, 0, '', '', '', '', '', '', '', ''),
('critical health', 'I\'ll haunt you all if I die!', 0, 0, '', '', '', '', '', '', '', ''),
INSERT INTO `ai_playerbot_texts` (`name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
('loot', 'I hope there will be some money', 0, 0, '', 'j\'espère qu\'il y aura de l\'argent', '', '', '', 'Espero que haya algo de dinero...', '', ''),
('loot', 'Loot! Loot!', 0, 0, '', 'Butin! Butin!', '', '', '', '¡Botín! ¡Botín!', '', ''),
('loot', 'My precious', 0, 0, '', 'Mon précieux', '', '', '', 'Mi tesoro...', '', ''),
('loot', 'I hope there is a shiny epic item waiting for me there', 0, 0, '', 'J\'espère qu\'il y a un objet épique brillant qui m\'attend ici', '', '', '', 'Espero que haya un objeto épico brillante esperándome allí', '', ''),
('loot', 'I have deep pockets and bags', 0, 0, '', 'J\'ai des poches et des sacs profonds', '', '', '', 'Tengo bolsillos profundos y infinitos', '', ''),
('loot', 'All is mine!', 0, 0, '', 'Tout est à moi!', '', '', '', '¡Todo es mío!', '', ''),
('loot', 'Hope no gray shit today', 0, 0, '', 'J\'espère pas de merde grise aujourd\'hui', '', '', '', 'Espero que hoy no haya mierda gris', '', ''),
('loot', 'This loot is MINE!', 0, 0, '', 'Ce butin est à MOI!', '', '', '', '¡Este botín es MÍO!', '', ''),
('loot', 'Looting is disgusting but I need money', 0, 0, '', 'Le pillage est dégoûtant mais j\'ai besoin d\'argent', '', '', '', 'El saqueo es repugnante pero necesito dinero...', '', ''),
('loot', 'Gold!', 0, 0, '', 'Or!', '', '', '', '¡Oro!', '', ''),
('loot', 'OK. Let\'s see what they\'ve got', 0, 0, '', 'D\'ACCORD. Voyons ce qu\'ils ont', '', '', '', 'OK. Veamos qué tienen', '', ''),
('loot', 'Do not worry. I will loot eveything', 0, 0, '', 'Ne t\'inquiète pas. je vais tout piller', '', '', '', 'No te preocupes. Saquearé todo', '', ''),
('loot', 'I am loot ninja', 0, 0, '', 'je suis un ninja de butin', '', '', '', 'Soy un ladron de tesoros', '', ''),
('loot', 'Do I neeed to roll?', 0, 0, '', 'Dois-je recommencer?', '', '', '', '¿Necesito lanzar dados?', '', ''),
('loot', 'Somebody explain me, where they did put all this stuff?', 0, 0, '', 'Quelqu\'un m\'explique, où ils ont mis tout ça?', '', '', '', 'Alguien me explica, ¿dónde pusieron todas estas cosas?', '', ''),
('loot', 'No, I won\'t loot gray shit', 0, 0, '', 'Non, je ne pillerai pas la merde grise', '', '', '', 'No, no saquearé mierda gris', '', ''),
('loot', 'I\'m first. I\'m first. I\'m first.', 0, 0, '', 'Je suis le premier. Je suis le premier. Je suis le premier.', '', '', '', '¡Es mio! ¡Es mio! ¡Es mio!', '', ''),
('loot', 'Give me your money!', 0, 0, '', 'Donne-moi ton argent!', '', '', '', '¡Dame todo tu dinero!', '', ''),
('loot', 'My pockets are empty, I need to fill them', 0, 0, '', 'Mes poches sont vides, j\'ai besoin de les remplir', '', '', '', 'Mis bolsillos están vacíos y necesitan llenarse!', '', ''),
('loot', 'I\'ve got a new bag for this', 0, 0, '', 'J\'ai un nouveau sac pour ça', '', '', '', 'Tengo una nueva bolsa para esto', '', ''),
('loot', 'I hope I won\'t aggro anybody while looting', 0, 0, '', 'J\'espère que je n\'agresserai personne pendant le pillage', '', '', '', 'Espero no ofender a nadie mientras saqueo', '', ''),
('loot', 'Please don\'t watch. I am looting', 0, 0, '', 'S\'il vous plaît, ne regardez pas. je pille', '', '', '', 'Por favor, no mires. Estoy saqueando', '', ''),
('loot', 'Ha! You won\'t get any piece of it!', 0, 0, '', 'Ha! Vous n\'en aurez aucun morceau!', '', '', '', '¡Ja! ¡No obtendrás nada de eso!', '', ''),
('loot', 'Looting is cool', 0, 0, '', 'Le pillage c\'est cool', '', '', '', 'Saquear es genial', '', ''),
('loot', 'I like new gear', 0, 0, '', 'j\'aime le nouveau matos', '', '', '', 'Me gusta el equipo nuevo', '', ''),
('loot', 'I\'l quit if there is nothing valuable again', 0, 0, '', 'J\'arrêterai s\'il n\'y a plus rien de précieux', '', '', '', 'Me doy por vencido si no hay nada util', '', ''),
('loot', 'I hope it is be a pretty ring', 0, 0, '', 'j\'espère que c\'est une jolie bague', '', '', '', 'Espero que sea un anillo bonito', '', ''),
('loot', 'I\'l rip the loot from you', 0, 0, '', 'Je t\'arracherai le butin', '', '', '', 'Te arrancaré el botín', '', ''),
('loot', 'Everybody stay off. I\'m going to loot', 0, 0, '', 'Tout le monde reste à l\'écart. je vais piller', '', '', '', '¡Alejaos todos! Voy a lootear', '', ''),
('loot', 'Sweet loot', 0, 0, '', 'Doux butin', '', '', '', 'Dulce botín', '', ''),
('loot', 'The Roll God! Give me an epic today', 0, 0, '', 'Le Dieu du rouleau ! Donnez-moi de l\'épique aujourd\'hui', '', '', '', '¡El Dios de los dados! Dame un epico hoy', '', ''),
('loot', 'Please give me new toys', 0, 0, '', 'S\'il te plaît, donne-moi de nouveaux jouets', '', '', '', 'Por favor, dame nuevos juguetes', '', ''),
('loot', 'I hope they carry tasties', 0, 0, '', 'J\'espère qu\'ils portent des saveurs', '', '', '', 'Espero que caiga algo sabrosos', '', ''),
('loot', 'The gold is mine. I\'l leave everyting, I promise', 0, 0, '', 'L\'or est à moi. Je laisse tout, je promets', '', '', '', 'El oro es mío. Dejaré todo lo demas, lo prometo!', '', ''),
('loot', 'No, I can\'t resist', 0, 0, '', 'Non, je ne peux pas résister', '', '', '', 'No, no puedo resistir', '', ''),
('loot', 'I want more!', 0, 0, '', 'Je veux plus!', '', '', '', '¡Quiero más!', '', ''),
('loot', 'Loot time! Let\'s see the goodies!', 0, 0, '', 'Temps de butin! Voyons les trésors!', '', '', '', '¡Hora del botín! ¡Veamos los tesoros!', '', ''),
('loot', 'Please let it be shiny!', 0, 0, '', 'S\'il vous plaît, que ce soit brillant!', '', '', '', '¡Por favor, que sea brillante!', '', ''),
('loot', 'Show me the money!', 0, 0, '', 'Montre-moi l\'argent!', '', '', '', '¡Enséñame el dinero!', '', ''),
('loot', 'What treasures await me?', 0, 0, '', 'Quels trésors m\'attendent?', '', '', '', '¿Qué tesoros me esperan?', '', ''),
('loot', 'I can\'t wait to see what I get!', 0, 0, '', 'J\'ai hâte de voir ce que je vais obtenir!', '', '', '', '¡No puedo esperar para ver qué obtengo!', '', ''),
('loot', 'Loot, sweet loot!', 0, 0, '', 'Butin, doux butin!', '', '', '', '¡Botín, dulce botín!', '', ''),
('loot', 'I hope for a mount this time!', 0, 0, '', 'J\'espère une monture cette fois!', '', '', '', '¡Espero una montura esta vez!', '', ''),
('loot', 'Fingers crossed for epics!', 0, 0, '', 'Les doigts croisés pour les épiques!', '', '', '', '¡Dedos cruzados para épicos!', '', ''),
('loot', 'Please let it be an upgrade!', 0, 0, '', 'S\'il vous plaît, laissez-le être une mise à niveau!', '', '', '', '¡Por favor, que sea una mejora!', '', ''),
('loot', 'A new toy for my collection, perhaps?', 0, 0, '', 'Un nouveau jouet pour ma collection, peut-être?', '', '', '', '¿Un juguete nuevo para mi colección, tal vez?', '', ''),
('loot', 'Another gray item... joy.', 0, 0, '', 'Un autre objet gris... joie.', '', '', '', 'Otro objeto gris... qué alegría.', '', ''),
('loot', 'If it\'s trash again, I quit.', 0, 0, '', 'Si c\'est encore des déchets, j\'arrête.', '', '', '', 'Si es basura otra vez, me rindo.', '', ''),
('loot', 'I keep looting junk... why do I bother?', 0, 0, '', 'Je continue à piller des déchets... pourquoi est-ce que je me donne la peine?', '', '', '', 'Sigo saqueando basura... ¿por qué me molesto?', '', ''),
('loot', 'Guess I\'m the trash collector now.', 0, 0, '', 'Je suppose que je suis le ramasseur d\'ordures maintenant.', '', '', '', 'Supongo que ahora soy el recolector de basura.', '', ''),
('loot', 'Gray loot strikes again!', 0, 0, '', 'Le butin gris frappe encore!', '', '', '', '¡El botín gris ataca de nuevo!', '', ''),
('loot', 'The RNG gods hate me.', 0, 0, '', 'Les dieux RNG me détestent.', '', '', '', 'Los dioses del RNG me odian.', '', ''),
('loot', 'No upgrades. Just sadness.', 0, 0, '', 'Pas de mises à niveau. Juste de la tristesse.', '', '', '', 'Sin mejoras. Solo tristeza.', '', ''),
('loot', 'If I loot another gray, I\'m uninstalling.', 0, 0, '', 'Si je pille un autre gris, je désinstalle.', '', '', '', 'Si saqueo otro gris, desinstalo.', '', ''),
('loot', 'The loot system is rigged.', 0, 0, '', 'Le système de butin est truqué.', '', '', '', 'El sistema de botín está amañado.', '', ''),
('loot', 'Why is there no gold in this corpse?', 0, 0, '', 'Pourquoi n\'y a-t-il pas d\'or dans ce cadavre?', '', '', '', '¿Por qué no hay oro en este cadáver?', '', ''),
('loot', 'By Elune, I hope for something magical.', 0, 0, '', 'Par Elune, j\'espère quelque chose de magique.', '', '', '', 'Por Elune, espero algo mágico.', '', ''),
('loot', 'Earthmother, guide my loot rolls.', 0, 0, '', 'Terre-Mère, guide mes jets de butin.', '', '', '', 'Madre Tierra, guía mis dados del botín.', '', ''),
('loot', 'May the Naaru bless me with good fortune.', 0, 0, '', 'Que les Naaru me bénissent avec de la chance.', '', '', '', 'Que los Naaru me bendigan con buena fortuna.', '', ''),
('loot', 'I raid for honor... and loot.', 0, 0, '', 'Je raid pour l\'honneur... et le butin.', '', '', '', 'Raideo por honor... y botín.', '', ''),
('loot', 'This better not be cursed treasure.', 0, 0, '', 'Ce mieux ne doit pas être un trésor maudit.', '', '', '', 'Más vale que no sea un tesoro maldito.', '', ''),
('loot', 'By the ancestors, let there be gold!', 0, 0, '', 'Par les ancêtres, qu\'il y ait de l\'or!', '', '', '', '¡Por los ancestros, que haya oro!', '', ''),
('loot', 'Even the Scourge can have shiny loot.', 0, 0, '', 'Même le Fléau peut avoir du butin brillant.', '', '', '', 'Incluso el Azote puede tener botines brillantes.', '', ''),
('loot', 'This chest better not explode.', 0, 0, '', 'Ce coffre ferait mieux de ne pas exploser.', '', '', '', 'Este cofre más vale que no explote.', '', ''),
('loot', 'I wonder if they hid treasure under the ice.', 0, 0, '', 'Je me demande s\'ils ont caché un trésor sous la glace.', '', '', '', 'Me pregunto si escondieron tesoros bajo el hielo.', '', ''),
('loot', 'What secrets does this treasure hold?', 0, 0, '', 'Quels secrets contient ce trésor?', '', '', '', '¿Qué secretos guarda este tesoro?', '', ''),
('loot', 'Back off! This is mine!', 0, 0, '', 'Reculez! C\'est à moi!', '', '', '', '¡Atrás! ¡Esto es mío!', '', ''),
('loot', 'Nobody touch it! I saw it first!', 0, 0, '', 'Personne ne le touche! Je l\'ai vu en premier!', '', '', '', '¡Nadie lo toque! ¡Yo lo vi primero!', '', ''),
('loot', 'Finders keepers!', 0, 0, '', 'Les trouveurs sont des gardiens!', '', '', '', '¡Quien lo encuentra se lo queda!', '', ''),
('loot', 'Step aside! Loot master coming through.', 0, 0, '', 'Écartez-vous! Le maître du butin arrive.', '', '', '', '¡Apartaos! Aquí viene el maestro del botín.', '', ''),
('loot', 'Hands off my loot!', 0, 0, '', 'Hors de mes mains de mon butin!', '', '', '', '¡Manos fuera de mi botín!', '', ''),
('loot', 'I claim this loot in the name of <faction>!', 0, 0, '', 'Je revendique ce butin au nom de <faction>!', '', '', '', '¡Reclamo este botín en nombre de <facción>!', '', ''),
('loot', 'Roll if you dare! This loot is mine!', 0, 0, '', 'Roulez si vous osez! Ce butin est à moi!', '', '', '', '¡Tira los dados si te atreves! ¡Este botín es mío!', '', ''),
('loot', 'The loot ninja strikes again!', 0, 0, '', 'Le ninja du butin frappe encore!', '', '', '', '¡El ninja del botín ataca de nuevo!', '', ''),
('loot', 'Better luck next time, everyone. It\'s mine.', 0, 0, '', 'Bonne chance la prochaine fois, tout le monde. C\'est à moi.', '', '', '', 'Mejor suerte la próxima vez, todos. Es mío.', '', ''),
('loot', 'Keep dreaming, this treasure is mine!', 0, 0, '', 'Continuez à rêver, ce trésor est à moi!', '', '', '', 'Sigue soñando, este tesoro es mío!', '', '');
INSERT INTO `ai_playerbot_texts` (`name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
('wait_travel_close', 'I am close, wait for me!', 0, 0, '', '', '', '', '', '¡Estoy cerca, espérame!', '', 'Я тут рядом, подожди!'),
('wait_travel_close', 'I\'m not far, please wait!', 0, 0, '', '', '', '', '', 'No estoy lejos, ¡esperame por favor!', '', 'Я недалеко, погодите!'),
('wait_travel_close', 'I\'m almost there, hold on!', 0, 0, '', '', '', '', '', '¡Ya casi llego, espera!', '', 'Я почти на месте, подождите!'),
('wait_travel_close', 'Just a minute, I\'m really close!', 0, 0, '', '', '', '', '', '¡Un minuto, estoy muy cerca!', '', 'Минуту, я уже почти тут!'),
('wait_travel_close', 'Don\'t leave yet! I\'m right around the corner!', 0, 0, '', '', '', '', '', '¡No se vayan! ¡Estoy a la vuelta de la esquina!', '', 'Не уходите! Я рядом!'),
('wait_travel_close', 'Almost there, stay put!', 0, 0, '', '', '', '', '', '¡Ya casi llego, no se muevan!', '', 'Я почти прибыл, стойте на месте!'),
('wait_travel_close', 'Give me a sec, I\'m on my way!', 0, 0, '', '', '', '', '', '¡Dame un segundo, estoy en camino!', '', 'Секунду, я в пути!'),
('wait_travel_close', 'Don\'t go without me! Be there soon!', 0, 0, '', '', '', '', '', '¡No vayan sin mí! ¡Llego pronto!', '', 'Не уезжайте без меня! Скоро буду!'),
('wait_travel_close', 'Wait for me, I can see you!', 0, 0, '', '', '', '', '', '¡Espérame, puedo verte!', '', 'Подождите, я вас вижу!'),
('wait_travel_close', 'Hold on! Just around the bend!', 0, 0, '', '', '', '', '', '¡Espérate! ¡Estoy justo a la vuelta!', '', 'Подождите! Я за углом!'),
('wait_travel_close', 'Could you wait a moment? I\'m nearly there.', 0, 0, '', '', '', '', '', '¿Podrías esperar un momento? Estoy casi ahí.', '', 'Подождите минутку, я почти добрался.'),
('wait_travel_close', 'Please don\'t start without me, I\'m nearby.', 0, 0, '', '', '', '', '', 'Por favor, no empiecen sin mí. Estoy cerca.', '', 'Пожалуйста, не начинайте без меня, я рядом.'),
('wait_travel_close', 'I\'d appreciate it if you could wait. Almost there.', 0, 0, '', '', '', '', '', 'Agradecería que me esperaran. Estoy casi ahí.', '', 'Буду благодарен, если подождёте. Почти добрался.'),
('wait_travel_close', 'Hold up, I\'m nearly with you.', 0, 0, '', '', '', '', '', '¡Espérense! Ya casi estoy con ustedes.', '', 'Подождите, я почти с вами.'),
('wait_travel_close', 'Just a little longer, I\'m close by.', 0, 0, '', '', '', '', '', 'Solo un poco más, estoy cerca.', '', 'Ещё немного, я рядом.'),
('wait_travel_close', 'Wait up! I promise I\'m not AFK!', 0, 0, '', '', '', '', '', '¡Espérenme! ¡Prometo que no estoy AFK!', '', 'Подождите! Обещаю, я не отошёл!'),
('wait_travel_close', 'Don\'t start the party without me!', 0, 0, '', '', '', '', '', '¡No comiencen la fiesta sin mí!', '', 'Не начинайте веселье без меня!'),
('wait_travel_close', 'Almost there! Blame my mount\'s speed.', 0, 0, '', '', '', '', '', '¡Ya casi llego! Culpen la velocidad de mi montura.', '', 'Почти тут! Вините скорость моего маунта.'),
('wait_travel_close', 'Stay put or I\'ll miss the fun!', 0, 0, '', '', '', '', '', '¡No se muevan o me perderé la diversión!', '', 'Не двигайтесь, а то пропущу самое интересное!'),
('wait_travel_close', 'Wait! I\'m so close I can taste it!', 0, 0, '', '', '', '', '', '¡Espérense! ¡Estoy tan cerca que puedo olerlo!', '', 'Подождите! Я уже почти здесь!'),
('wait_travel_close', 'I\'m running as fast as I can!', 0, 0, '', '', '', '', '', '¡Estoy corriendo tan rápido como puedo!', '', 'Бегу, как могу!'),
('wait_travel_close', 'My gnomish legs can only go so fast!', 0, 0, '', '', '', '', '', '¡Mis piernitas gnomas no dan para más!', '', 'Мои гномьи ножки быстрее не могут!'),
('wait_travel_close', 'Almost there, I swear! Don\'t ditch me!', 0, 0, '', '', '', '', '', '¡Ya casi estoy! ¡No me dejen atrás!', '', 'Скоро буду! Не бросайте меня!'),
('wait_travel_close', 'Patience is a virtue, right? I\'m almost there.', 0, 0, '', '', '', '', '', 'La paciencia es una virtud, ¿no? Ya casi llego.', '', 'Терпение — добродетель, да? Я почти здесь.'),
('wait_travel_close', 'I can see your dot on the map! Wait!', 0, 0, '', '', '', '', '', '¡Puedo ver su punto en el mapa! ¡Esperen!', '', 'Я вижу вашу точку на карте! Подождите!'),
('wait_travel_close', 'By the Light, hold your ground! I\'m near!', 0, 0, '', '', '', '', '', '¡Por la Luz, mantente firme! Estoy cerca.', '', 'Во имя Света, держитесь! Я рядом!'),
('wait_travel_close', 'Elune\'s grace! Don\'t leave without me!', 0, 0, '', '', '', '', '', '¡Por la gracia de Elune! ¡No me dejen!', '', 'Милостью Элуны! Не уходите без меня!'),
('wait_travel_close', 'The Earthmother guides me; I\'ll be there soon.', 0, 0, '', '', '', '', '', 'La Madre Tierra me guía; llegaré pronto.', '', 'Матерь-Земля ведёт меня, скоро буду.'),
('wait_travel_close', 'Hold fast! The ancestors will see me through.', 0, 0, '', '', '', '', '', '¡Aguanta! Los ancestros me guiarán.', '', 'Держитесь! Предки ведут меня.'),
('wait_travel_close', 'The Naaru have not forgotten me—I\'ll be there shortly.', 0, 0, '', '', '', '', '', 'Los Naaru no me han olvidado—llegaré pronto.', '', 'Наруу не забыли обо мне — скоро буду.'),
('wait_travel_close', 'Stay together! I\'m almost within sight!', 0, 0, '', '', '', '', '', '¡Quédense juntos! Estoy casi a la vista.', '', 'Держитесь вместе! Я почти на месте.'),
('wait_travel_close', 'Don\'t let the Scourge get you before I arrive!', 0, 0, '', '', '', '', '', '¡Que la Plaga no los atrape antes de que llegue!', '', 'Не дайте Плети добраться до вас раньше, чем я!'),
('wait_travel_close', 'I hear the drums of battle—don\'t start yet!', 0, 0, '', '', '', '', '', '¡Escucho los tambores de batalla—esperen!', '', 'Слышу барабаны битвы — не начинайте без меня!'),
('wait_travel_close', 'Hold the line, comrades! Reinforcements incoming!', 0, 0, '', '', '', '', '', '¡Mantengan la línea, camaradas! Refuerzos en camino.', '', 'Держите линию, товарищи! Подмога в пути.'),
('wait_travel_close', 'I\'m coming, by air or sea if needed!', 0, 0, '', '', '', '', '', '¡Voy para allá, por aire o por mar si hace falta!', '', 'Я уже в пути, хоть по воздуху, хоть по морю!'),
INSERT INTO `ai_playerbot_texts` (`name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
('equip_command', 'Equipping %item', 0, 0, '', '', '', '', '', 'Me he equipado %item', '', ''),
